	private JoinOrderPlanner.JoinOrderPlan toJoinOrderPlan(StatePlan result, JoinOrderPlanner.Algorithm algorithm) {
		List<TupleExpr> orderedArgs = new ArrayList<>(result.order().size());
		for (Integer index : result.order()) {
			orderedArgs.add(factors.get(index.intValue()).tupleExpr());
		}
		Map<String, String> summaryStringMetrics = new HashMap<>();
		summaryStringMetrics.put(TelemetryMetricNames.PLANNER_ID, "sketch");
		summaryStringMetrics.put(TelemetryMetricNames.PLANNER_ALGORITHM, algorithm.name());
		summaryStringMetrics.put(TelemetryMetricNames.PLANNER_PATH,
				SketchBasedJoinEstimator.SketchPlannerPath.ROBUST_USED.name());
		summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_LOGICAL_EXPLORATION,
				logicalExplorationSummary());
		summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_RUNTIME_HINTS,
				runtimeCorrectionHints());
		summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_RUNTIME_FEEDBACK,
				runtimeFeedbackSummary());
		if (traceDiagnostics && !diagnostics.isEmpty()) {
			summaryStringMetrics.put(TelemetryMetricNames.OPTIMIZER_PLANNER_DIAGNOSTICS,
					summarizeDiagnostics(diagnostics));
		}
		Map<String, Double> summaryDoubleMetrics = new HashMap<>();
		summaryDoubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, result.totalWork());
		double runtimeFeedbackConfidence = runtimeFeedbackConfidence();
		if (Double.isFinite(runtimeFeedbackConfidence)) {
			summaryDoubleMetrics.put(TelemetryMetricNames.OPTIMIZER_RUNTIME_FEEDBACK_CONFIDENCE,
					runtimeFeedbackConfidence);
		}
		List<JoinOrderPlanner.PlanStep> steps = buildPlanSteps(result.order());
		double totalWork = sumStepWorkRows(steps);
		summaryDoubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, totalWork);
		return new JoinOrderPlanner.JoinOrderPlan(List.copyOf(orderedArgs), result.estimate().outputRows(),
				totalWork, List.copyOf(diagnostics), summaryStringMetrics, summaryDoubleMetrics, steps);
	}

	private double sumStepWorkRows(List<JoinOrderPlanner.PlanStep> steps) {
		double total = 0.0d;
		for (JoinOrderPlanner.PlanStep step : steps) {
			double stepWorkRows = step.getStepWorkRows();
			if (!isFiniteNonNegative(stepWorkRows)) {
				return Double.NaN;
			}
			total += stepWorkRows;
		}
		return total;
	}

	private FactorBuildResult buildFactors(List<TupleExpr> expressions) {
		List<PendingPlanFactor> pendingFactors = new ArrayList<>(expressions.size());
		LinkedHashSet<String> providedVars = new LinkedHashSet<>(initiallyBoundVars);
		for (int i = 0; i < expressions.size(); i++) {
			TupleExpr tupleExpr = expressions.get(i);
			SketchBasedJoinEstimator.TuplePlanEstimate estimate = estimator.factorEstimateForJoinOrdering(tupleExpr,
					initiallyBoundVars);
			if (estimate == null) {
				return new FactorBuildResult(List.of(), unsupportedPath(tupleExpr), tupleExpr);
			}
			Set<String> bindingVars = factorBindingVars(tupleExpr);
			providedVars.addAll(bindingVars);
			pendingFactors.add(new PendingPlanFactor(i, tupleExpr, estimate, bindingVars));
		}
		List<PlanFactor> builtFactors = new ArrayList<>(pendingFactors.size());
		for (PendingPlanFactor pending : pendingFactors) {
			Set<String> connectivityVars = connectivityVars(pending.tupleExpr(), pending.joinVars(),
					providedVars);
			builtFactors.add(new PlanFactor(pending.index(), pending.tupleExpr(), pending.estimate(),
					pending.joinVars(), connectivityVars, pending.joinVars()));
		}
		return new FactorBuildResult(List.copyOf(builtFactors), null, null);
	}

	private static Set<String> factorBindingVars(TupleExpr tupleExpr) {
		if (tupleExpr instanceof BindingSetAssignment) {
			return plannerVariables(tupleExpr.getBindingNames());
		}
		if (tupleExpr instanceof Filter filter) {
			return factorBindingVars(filter.getArg());
		}
		return plannerVariables(VarNameCollector.process(tupleExpr));
	}

	private static Set<String> plannerVariables(Set<String> variables) {
		if (variables == null || variables.isEmpty()) {
			return Set.of();
		}
		LinkedHashSet<String> plannerVariables = new LinkedHashSet<>();
		for (String variable : variables) {
			if (isPlannerVariableName(variable)) {
				plannerVariables.add(variable);
			}
		}
		return Set.copyOf(plannerVariables);
	}

	private static Set<String> connectivityVars(TupleExpr tupleExpr, Set<String> joinVars, Set<String> providedVars) {
		LinkedHashSet<String> variables = new LinkedHashSet<>(joinVars);
		addProvidedFilterConditionVars(tupleExpr, providedVars, variables);
		return Set.copyOf(variables);
	}

	private static void addProvidedFilterConditionVars(TupleExpr tupleExpr, Set<String> providedVars,
			Set<String> variables) {
		if (!(tupleExpr instanceof Filter filter)) {
			return;
		}
		for (String conditionVar : VarNameCollector.process(filter.getCondition())) {
			if (providedVars.contains(conditionVar)) {
				variables.add(conditionVar);
			}
		}
		addProvidedFilterConditionVars(filter.getArg(), providedVars, variables);
	}

	private static Map<String, Integer> buildVariableIds(Set<String> initiallyBoundVars,
			List<JoinOrderPlanner.FilterConstraint> deferredFilters, List<PlanFactor> factors) {
		Map<String, Integer> ids = new HashMap<>();
		registerVariables(ids, initiallyBoundVars);
		for (JoinOrderPlanner.FilterConstraint filter : deferredFilters) {
			registerVariables(ids, filter.getRequiredVars());
		}
		for (PlanFactor factor : factors) {
			registerVariables(ids, factor.joinVars());
			registerVariables(ids, factor.connectivityVars());
			registerVariables(ids, factor.bindingVars());
		}
		return Map.copyOf(ids);
	}

	private static void registerVariables(Map<String, Integer> ids, Set<String> variables) {
		for (String variable : variables) {
			if (!isPlannerVariableName(variable) || ids.containsKey(variable)) {
				continue;
			}
			if (ids.size() >= Long.SIZE) {
				return;
			}
			ids.put(variable, ids.size());
		}
	}

	private static boolean isPlannerVariableName(String variable) {
		return variable != null && !variable.startsWith("_const_");
	}

	private static String[] buildVariableNames(Map<String, Integer> variableIds) {
		String[] names = new String[variableIds.size()];
		for (Map.Entry<String, Integer> entry : variableIds.entrySet()) {
			names[entry.getValue().intValue()] = entry.getKey();
		}
		return names;
	}

	private static long[] buildFactorMasks(List<PlanFactor> factors, Map<String, Integer> variableIds,
			PlanFactorMaskKind kind) {
		long[] masks = new long[factors.size()];
		for (int i = 0; i < factors.size(); i++) {
			PlanFactor factor = factors.get(i);
			Set<String> variables = switch (kind) {
			case JOIN -> factor.joinVars();
			case CONNECTIVITY -> factor.connectivityVars();
			case BINDING -> factor.bindingVars();
			};
			masks[i] = variableMask(variables, variableIds);
		}
		return masks;
	}

	private static long[] buildRuntimeVarMasks(List<PlanFactor> factors, Map<String, Integer> variableIds) {
		long[] masks = new long[factors.size()];
		for (int i = 0; i < factors.size(); i++) {
			masks[i] = variableMask(factorBindingVars(factors.get(i).tupleExpr()), variableIds);
		}
		return masks;
	}

	private static long[] buildDeferredFilterRequiredVarMasks(List<JoinOrderPlanner.FilterConstraint> deferredFilters,
			Map<String, Integer> variableIds) {
		long[] masks = new long[deferredFilters.size()];
		for (int i = 0; i < deferredFilters.size(); i++) {
			masks[i] = variableMask(deferredFilters.get(i).getRequiredVars(), variableIds);
		}
		return masks;
	}

	private static long variableMask(Set<String> variables, Map<String, Integer> variableIds) {
		long mask = 0L;
		for (String variable : variables) {
			Integer id = variableIds.get(variable);
			if (id != null) {
				mask |= 1L << id.intValue();
			}
		}
		return mask;
	}

	private SketchBasedJoinEstimator.SketchPlannerPath classifyGraph() {
		List<Set<Integer>> physicalComponents = physicalComponents();
		int requiredPhysicalComponents = 0;
		Set<Integer> requiredFactors = new LinkedHashSet<>();
		for (Set<Integer> component : physicalComponents) {
			if (!isIgnorableSmallBindingSetAssignmentComponent(component)) {
				requiredPhysicalComponents++;
				requiredFactors.addAll(component);
			}
		}
		int edgeCount = 0;
		Set<String> variables = new LinkedHashSet<>();
		for (PlanFactor factor : factors) {
			edgeCount += factor.arity();
			variables.addAll(factor.connectivityVars());
		}
		boolean cyclicOrDense = edgeCount != factors.size() + variables.size() - physicalComponents.size();
		recordDebug("graph classification: physicalComponents=" + physicalComponents.size()
				+ " requiredPhysicalComponents=" + requiredPhysicalComponents + " variables="
				+ new TreeSet<>(variables) + " edgeCount=" + edgeCount + " cyclicOrDense=" + cyclicOrDense);
		return null;
	}

	private List<Set<Integer>> physicalComponents() {
		Set<Integer> seenFactors = new LinkedHashSet<>();
		List<Set<Integer>> components = new ArrayList<>();
		for (int i = 0; i < factors.size(); i++) {
			if (seenFactors.contains(i)) {
				continue;
			}
			components.add(physicalComponent(i, seenFactors));
		}
		return List.copyOf(components);
	}

	private Set<Integer> physicalComponent(int startFactor, Set<Integer> seenFactors) {
		Set<Integer> component = new LinkedHashSet<>();
		Set<String> seenVariables = new LinkedHashSet<>();
		ArrayDeque<Object> queue = new ArrayDeque<>();
		queue.add(Integer.valueOf(startFactor));
		seenFactors.add(startFactor);
		component.add(startFactor);
		while (!queue.isEmpty()) {
			Object next = queue.removeFirst();
			if (next instanceof Integer factorIndex) {
				for (String variable : factors.get(factorIndex.intValue()).connectivityVars()) {
					if (seenVariables.add(variable)) {
						queue.addLast(variable);
					}
				}
				continue;
			}
			String variable = (String) next;
			for (int i = 0; i < factors.size(); i++) {
				if (!seenFactors.contains(i) && factors.get(i).connectivityVars().contains(variable)) {
					seenFactors.add(i);
					component.add(i);
					queue.addLast(Integer.valueOf(i));
				}
			}
		}
		return Set.copyOf(component);
	}

	private boolean isIgnorableSmallBindingSetAssignmentComponent(Set<Integer> component) {
		if (component.isEmpty()) {
			return false;
		}
		for (Integer factorIndex : component) {
			if (!isSmallBindingSetAssignment(factorIndex.intValue())) {
				return false;
			}
		}
		return true;
	}

	private boolean isConnectedWithDeferredFilters(Set<Integer> requiredFactors) {
		if (requiredFactors.isEmpty()) {
			return true;
		}
		Set<Integer> seenFactors = new LinkedHashSet<>();
		Set<String> seenVariables = new LinkedHashSet<>();
		ArrayDeque<Object> queue = new ArrayDeque<>();
		Integer startFactor = requiredFactors.iterator().next();
		queue.add(startFactor);
		seenFactors.add(startFactor);
		while (!queue.isEmpty()) {
			Object next = queue.removeFirst();
			if (next instanceof Integer factorIndex) {
				for (String variable : factors.get(factorIndex.intValue()).connectivityVars()) {
					if (seenVariables.add(variable)) {
						queue.addLast(variable);
					}
				}
				continue;
			}
			String variable = (String) next;
			for (int i = 0; i < factors.size(); i++) {
				if (!seenFactors.contains(i) && factors.get(i).connectivityVars().contains(variable)) {
					seenFactors.add(i);
					queue.addLast(Integer.valueOf(i));
				}
			}
			for (String connectedVariable : deferredFilterVariablesConnectedTo(variable)) {
				if (seenVariables.add(connectedVariable)) {
					queue.addLast(connectedVariable);
				}
			}
		}
		return seenFactors.containsAll(requiredFactors);
	}

	private List<String> deferredFilterVariablesConnectedTo(String variable) {
		if (deferredFilters.isEmpty()) {
			return List.of();
		}
		LinkedHashSet<String> connected = new LinkedHashSet<>();
		for (JoinOrderPlanner.FilterConstraint filter : deferredFilters) {
			Set<String> requiredVars = filter.getRequiredVars();
			if (!requiredVars.contains(variable)) {
				continue;
			}
			for (String requiredVar : requiredVars) {
				if (!requiredVar.equals(variable)) {
					connected.add(requiredVar);
				}
			}
		}
		return List.copyOf(connected);
	}

	private StatePlan seedPlan(int factorIndex) {
		long seedMask = bit(factorIndex);
		PlanFactor factor = factors.get(factorIndex);
		SketchBasedJoinEstimator.TuplePlanEstimate conditionedEstimate = conditionedFactorEstimate(factorIndex,
				initiallyBoundVarMask);
		FactorPhysicalEstimate physicalEstimate = factorPhysicalEstimate(factorIndex, 0L, initiallyBoundVarMask,
				conditionedEstimate.outputRows(), null);
		SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate = factor.estimate();
		double rowsProcessed = rowsProcessedByStep(factorIndex, 0L, null, factor.estimate().outputRows());
		double stepWorkRows = stepWorkRows(0L, seedMask, physicalEstimate.workRows(), rowsProcessed,
				rowsEnteringEstimate);
		SketchBasedJoinEstimator.TuplePlanEstimate seedEstimate = applyUnlockedFilters(0L, seedMask,
				rowsEnteringEstimate);
		return new StatePlan(seedMask, List.of(factorIndex), seedEstimate, stepWorkRows,
				List.of(physicalStepRank(physicalEstimate)));
	}

	private StatePlan extendPlan(StatePlan prefix, int candidate) {
		long mask = prefix.mask();
		long currentBoundVarMask = boundVariableMask(mask);
		SketchBasedJoinEstimator.JoinStepEstimate step = estimateTransition(mask, prefix.estimate(), candidate);
		long nextMask = mask | bit(candidate);
		SketchBasedJoinEstimator.TuplePlanEstimate conditionedEstimate = conditionedFactorEstimate(candidate,
				currentBoundVarMask);
		FactorPhysicalEstimate physicalEstimate = factorPhysicalEstimate(candidate, mask, currentBoundVarMask,
				conditionedEstimate.outputRows(), prefix.estimate());
		SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate = rowsEnteringEstimate(mask, candidate,
				prefix.estimate(), step);
		double rowsProcessed = rowsProcessedByStep(candidate, mask, prefix.estimate(),
				rowsEnteringEstimate.outputRows());
		double stepWorkRows = stepWorkRows(mask, nextMask, physicalEstimate.workRows(), rowsProcessed,
				rowsEnteringEstimate);
		SketchBasedJoinEstimator.TuplePlanEstimate nextEstimate = applyUnlockedFilters(mask, nextMask,
				rowsEnteringEstimate);
		List<Integer> nextOrder = new ArrayList<>(prefix.order().size() + 1);
		nextOrder.addAll(prefix.order());
		nextOrder.add(candidate);
		List<PhysicalStepRank> nextPhysicalStepRanks = new ArrayList<>(prefix.physicalStepRanks().size() + 1);
		nextPhysicalStepRanks.addAll(prefix.physicalStepRanks());
		nextPhysicalStepRanks.add(physicalStepRank(physicalEstimate));
		return new StatePlan(nextMask, List.copyOf(nextOrder), nextEstimate, prefix.totalWork() + stepWorkRows,
				List.copyOf(nextPhysicalStepRanks));
	}

	private PhysicalStepRank physicalStepRank(FactorPhysicalEstimate physicalEstimate) {
		return new PhysicalStepRank(physicalEstimate.physicalComparable(),
				physicalEstimate.missingLookupComponents(), physicalEstimate.directLookup(),
				physicalEstimate.factorOutputRows(), physicalEstimate.workRows(),
				physicalEstimate.lookupComponents(), physicalEstimate.lookupComponentMask(),
				physicalEstimate.accessRowsBeforeFilter());
	}

	private StatePlan optimizeGreedy() {
		logicalExplorationMode = "greedy-beam";
		StateFrontier beam = new StateFrontier(GREEDY_BEAM_WIDTH);
		long seedCandidateMask = seedCandidateMask();
		while (seedCandidateMask != 0L) {
			int i = Long.numberOfTrailingZeros(seedCandidateMask);
			seedCandidateMask &= seedCandidateMask - 1L;
			StatePlan seedPlan = seedPlan(i);
			boolean accepted = beam.add(seedPlan);
			if (traceDiagnostics) {
				recordDebug("greedy seed candidate: " + describeAlternative(0L, null, i, seedPlan, 0.0d,
						accepted));
			}
			recordLogicalCandidate(beam, accepted);
		}
		if (beam.isEmpty()) {
			return null;
		}

		logicalFinalFrontierWidth = beam.size();
		recordDebug("greedy seed: width=" + beam.size() + " limit=" + GREEDY_BEAM_WIDTH);
		for (int depth = 1; depth < factors.size(); depth++) {
			StateFrontier nextBeam = new StateFrontier(GREEDY_BEAM_WIDTH);
			for (StatePlan prefix : beam.plans()) {
				long mask = prefix.mask();
				long candidateMask = candidatesMask(mask);
				while (candidateMask != 0L) {
					int candidate = Long.numberOfTrailingZeros(candidateMask);
					candidateMask &= candidateMask - 1L;
					String connection = traceDiagnostics ? connectionReason(mask, candidate) : null;
					StatePlan candidatePlan = extendPlan(prefix, candidate);
					boolean accepted = nextBeam.add(candidatePlan);
					if (traceDiagnostics) {
						recordDebug("greedy candidate: " + describeAlternative(mask, prefix, candidate,
								candidatePlan, prefix.totalWork(), accepted) + " sharedVar=" + connection
								+ " boundVars=" + new TreeSet<>(boundVariables(mask)));
					}
					recordLogicalCandidate(nextBeam, accepted);
				}
			}
			if (nextBeam.isEmpty()) {
				return null;
			}
			beam = nextBeam;
			logicalFinalFrontierWidth = beam.size();
			recordDebug("greedy choose: depth=" + depth + " width=" + beam.size() + " bestOrder="
					+ describeFactorOrder(beam.best().order()) + " bestWorkRows=" + beam.best().totalWork());
		}

		return beam.best();
	}

	private StatePlan optimizeDynamicProgramming() {
		logicalExplorationMode = "dp-frontier";
		if (stateMemoSize > 0) {
			return optimizeDynamicProgrammingArray();
		}
		long all = allMask();
		Map<Long, StateFrontier> frontierByMask = new HashMap<>();
		Map<Integer, LinkedHashSet<Long>> statesBySize = new HashMap<>();
		long seedCandidateMask = seedCandidateMask();
		while (seedCandidateMask != 0L) {
			int i = Long.numberOfTrailingZeros(seedCandidateMask);
			seedCandidateMask &= seedCandidateMask - 1L;
			StatePlan seedPlan = seedPlan(i);
			StateFrontier frontier = frontierByMask.computeIfAbsent(seedPlan.mask(),
					ignored -> new StateFrontier(FRONTIER_LIMIT));
			boolean accepted = frontier.add(seedPlan);
			recordLogicalCandidate(frontier, accepted);
			statesBySize.computeIfAbsent(1, ignored -> new LinkedHashSet<>()).add(seedPlan.mask());
			if (traceDiagnostics) {
				recordDebug("dp seed: " + describeAlternative(0L, null, i, seedPlan, 0.0d, accepted));
			}
		}

		for (int size = 1; size < factors.size(); size++) {
			for (long mask : statesBySize.getOrDefault(size, new LinkedHashSet<>())) {
				StateFrontier frontier = frontierByMask.get(mask);
				if (frontier == null || frontier.isEmpty()) {
					continue;
				}
				for (StatePlan prefix : frontier.plans()) {
					long candidateMask = candidatesMask(mask);
					while (candidateMask != 0L) {
						int candidate = Long.numberOfTrailingZeros(candidateMask);
						candidateMask &= candidateMask - 1L;
						String connection = traceDiagnostics ? connectionReason(mask, candidate) : null;
						StatePlan candidatePlan = extendPlan(prefix, candidate);
						StateFrontier nextFrontier = frontierByMask.computeIfAbsent(candidatePlan.mask(),
								ignored -> new StateFrontier(FRONTIER_LIMIT));
						boolean accepted = nextFrontier.add(candidatePlan);
						recordLogicalCandidate(nextFrontier, accepted);
						if (traceDiagnostics) {
							recordDebug("dp candidate: " + describeAlternative(mask, prefix, candidate,
									candidatePlan, prefix.totalWork(), accepted) + " sharedVar=" + connection);
						}
						if (accepted) {
							statesBySize.computeIfAbsent(size + 1, ignored -> new LinkedHashSet<>())
									.add(candidatePlan.mask());
						}
					}
				}
			}
		}

		StateFrontier finalFrontier = frontierByMask.get(all);
		logicalFinalFrontierWidth = finalFrontier == null ? 0 : finalFrontier.size();
		recordDebug("dp frontier: finalWidth=" + (finalFrontier == null ? 0 : finalFrontier.size()) + " limit="
				+ FRONTIER_LIMIT);
		return finalFrontier == null ? null : finalFrontier.best();
	}

	private StatePlan optimizeDynamicProgrammingArray() {
		logicalExplorationMode = "dp-frontier";
		long all = allMask();
		StateFrontier[] frontierByMask = new StateFrontier[stateMemoSize];
		long seedCandidateMask = seedCandidateMask();
		while (seedCandidateMask != 0L) {
			int i = Long.numberOfTrailingZeros(seedCandidateMask);
			seedCandidateMask &= seedCandidateMask - 1L;
			StatePlan seedPlan = seedPlan(i);
			frontierByMask[(int) seedPlan.mask()] = new StateFrontier(FRONTIER_LIMIT);
			boolean accepted = frontierByMask[(int) seedPlan.mask()].add(seedPlan);
			recordLogicalCandidate(frontierByMask[(int) seedPlan.mask()], accepted);
			if (traceDiagnostics) {
				recordDebug("dp seed: " + describeAlternative(0L, null, i, seedPlan, 0.0d, accepted));
			}
		}

		for (int size = 1; size < factors.size(); size++) {
			for (int maskIndex = 1; maskIndex < stateMemoSize; maskIndex++) {
				if (Integer.bitCount(maskIndex) != size) {
					continue;
				}
				long mask = maskIndex;
				StateFrontier frontier = frontierByMask[maskIndex];
				if (frontier == null || frontier.isEmpty()) {
					continue;
				}
				for (StatePlan prefix : frontier.plans()) {
					long candidateMask = candidatesMask(mask);
					while (candidateMask != 0L) {
						int candidate = Long.numberOfTrailingZeros(candidateMask);
						candidateMask &= candidateMask - 1L;
						String connection = traceDiagnostics ? connectionReason(mask, candidate) : null;
						StatePlan candidatePlan = extendPlan(prefix, candidate);
						StateFrontier nextFrontier = frontierByMask[(int) candidatePlan.mask()];
						if (nextFrontier == null) {
							nextFrontier = new StateFrontier(FRONTIER_LIMIT);
							frontierByMask[(int) candidatePlan.mask()] = nextFrontier;
						}
						boolean accepted = nextFrontier.add(candidatePlan);
						recordLogicalCandidate(nextFrontier, accepted);
						if (traceDiagnostics) {
							recordDebug("dp candidate: " + describeAlternative(mask, prefix, candidate,
									candidatePlan, prefix.totalWork(), accepted) + " sharedVar=" + connection);
						}
					}
				}
			}
		}
		StateFrontier finalFrontier = frontierByMask[(int) all];
		logicalFinalFrontierWidth = finalFrontier == null ? 0 : finalFrontier.size();
		recordDebug("dp frontier: finalWidth=" + (finalFrontier == null ? 0 : finalFrontier.size()) + " limit="
				+ FRONTIER_LIMIT);
		return finalFrontier == null ? null : finalFrontier.best();
	}

	private long seedCandidateMask() {
		long candidates = candidatesMask(0L);
		if (candidates != 0L) {
			long fullyBoundGraphFactors = fullyBoundPreferredGraphFactors(candidates, boundVariableMask(0L));
			if (fullyBoundGraphFactors != 0L) {
				return fullyBoundGraphFactors;
			}
		}
		return allMask();
	}

	private long candidatesMask(long mask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			long candidates = candidateMaskByState[stateIndex];
			if (candidates == UNCOMPUTED_MASK) {
				candidates = computeCandidatesMask(mask);
				candidateMaskByState[stateIndex] = candidates;
			}
			return candidates;
		}
		return candidateMaskMemo.computeIfAbsent(mask, this::computeCandidatesMask);
	}

	private long computeCandidatesMask(long mask) {
		long preferred = 0L;
		long disconnected = 0L;
		long disconnectedSmallBindingAssignments = 0L;
		long disconnectedSubjectTypeGuards = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(mask, i)) {
				continue;
			}
			if (hasConnection(mask, i)) {
				preferred |= bit(i);
			} else {
				long bit = bit(i);
				disconnected |= bit;
				if (isSmallBindingSetAssignment(i)) {
					disconnectedSmallBindingAssignments |= bit;
				} else if (isSubjectTypeGuard(i)) {
					disconnectedSubjectTypeGuards |= bit;
				}
			}
		}
		if (preferred != 0L) {
			long fullyBoundPreferred = fullyBoundPreferredGraphFactors(preferred, boundVariableMask(mask));
			if (fullyBoundPreferred != 0L) {
				preferred = fullyBoundPreferred;
			}
		}
		if (preferred != 0L) {
			long subjectContinuationGuards = smallBindingAssignmentsForSubjectBoundPreferredBridge(mask, preferred,
					disconnectedSmallBindingAssignments);
			long bindingAssignmentGuards = subjectContinuationGuards != 0L
					? subjectContinuationGuards
					: smallBindingAssignmentsForPreferredBridge(mask, preferred, disconnectedSmallBindingAssignments);
			long guardedPreferred = subjectContinuationGuards != 0L ? 0L : preferred;
			long candidates = guardedPreferred
					| bindingAssignmentGuards
					| subjectTypeGuardsForPreferredBridge(mask, preferred, disconnectedSubjectTypeGuards);
			candidates = preferConnectedBridgeIntroducers(mask, candidates);
			return preferBoundSubjectTypeGuards(mask, candidates);
		}
		long candidates = disconnected;
		candidates = preferConnectedBridgeIntroducers(mask, candidates);
		return preferBoundSubjectTypeGuards(mask, candidates);
	}

	private long smallBindingAssignmentsForSubjectBoundPreferredBridge(long mask, long preferred,
			long disconnectedSmallBindingAssignments) {
		if (disconnectedSmallBindingAssignments == 0L) {
			return 0L;
		}
		long boundVars = boundVariableMask(mask);
		long subjectBoundIntroducedVars = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(preferred, i) || isBindingSetAssignment(i) || (subjectVarMask(i) & boundVars) == 0L) {
				continue;
			}
			subjectBoundIntroducedVars |= bindingVarMasks[i] & ~boundVars;
		}
		if (subjectBoundIntroducedVars == 0L) {
			return 0L;
		}
		long guards = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(disconnectedSmallBindingAssignments, i)
					&& (bindingVarMasks[i] & subjectBoundIntroducedVars) != 0L) {
				guards |= bit(i);
			}
		}
		return guards;
	}

	private long smallBindingAssignmentsForPreferredBridge(long mask, long preferred,
			long disconnectedSmallBindingAssignments) {
		if (disconnectedSmallBindingAssignments == 0L) {
			return 0L;
		}
		long boundVars = boundVariableMask(mask);
		if (hasFullyBoundPreferredGraphFactor(preferred, boundVars)) {
			return 0L;
		}
		long preferredIntroducedVars = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(preferred, i) && !isBindingSetAssignment(i)) {
				preferredIntroducedVars |= bindingVarMasks[i] & ~boundVars;
			}
		}
		if (preferredIntroducedVars == 0L) {
			return 0L;
		}
		long guards = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(disconnectedSmallBindingAssignments, i)
					&& (bindingVarMasks[i] & preferredIntroducedVars) != 0L) {
				guards |= bit(i);
			}
		}
		return guards;
	}

	private long fullyBoundPreferredGraphFactors(long preferred, long boundVars) {
		long fullyBound = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(preferred, i)
					&& !isBindingSetAssignment(i)
					&& (bindingVarMasks[i] & ~boundVars) == 0L) {
				fullyBound |= bit(i);
			}
		}
		return fullyBound;
	}

	private boolean hasFullyBoundPreferredGraphFactor(long preferred, long boundVars) {
		for (int i = 0; i < factors.size(); i++) {
			if (contains(preferred, i)
					&& !isBindingSetAssignment(i)
					&& (bindingVarMasks[i] & ~boundVars) == 0L) {
				return true;
			}
		}
		return false;
	}

	private long subjectTypeGuardsForPreferredBridge(long mask, long preferred, long disconnectedSubjectTypeGuards) {
		if (disconnectedSubjectTypeGuards == 0L) {
			return 0L;
		}
		long boundVars = boundVariableMask(mask);
		long preferredIntroducedVars = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(preferred, i)) {
				preferredIntroducedVars |= bindingVarMasks[i] & ~boundVars;
			}
		}
		if (preferredIntroducedVars == 0L) {
			return 0L;
		}
		long guards = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(disconnectedSubjectTypeGuards, i)
					&& (subjectVarMask(i) & preferredIntroducedVars) != 0L) {
				guards |= bit(i);
			}
		}
		return guards;
	}

	private long preferConnectedBridgeIntroducers(long mask, long candidates) {
		if (candidates == 0L) {
			return candidates;
		}
		long boundVars = boundVariableMask(mask);
		long connectedIntroducedVars = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(candidates, i) && !isSubjectTypeGuard(i) && hasConnection(mask, i)) {
				connectedIntroducedVars |= bindingVarMasks[i] & ~boundVars;
			}
		}
		if (connectedIntroducedVars == 0L) {
			return candidates;
		}
		long filtered = candidates;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(candidates, i)
					&& isSubjectTypeGuard(i)
					&& (subjectVarMask(i) & connectedIntroducedVars) != 0L) {
				filtered &= ~bit(i);
			}
		}
		return filtered == 0L ? candidates : filtered;
	}

	private long preferBoundSubjectTypeGuards(long mask, long candidates) {
		if (candidates == 0L) {
			return candidates;
		}
		long boundVars = boundVariableMask(mask);
		long guardSubjects = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(candidates, i) && isSubjectTypeGuard(i)) {
				guardSubjects |= subjectVarMask(i) & boundVars;
			}
		}
		if (guardSubjects == 0L) {
			return candidates;
		}
		long filtered = candidates;
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(candidates, i) || isSubjectTypeGuard(i)
					|| (subjectVarMask(i) & guardSubjects) == 0L
					|| introducesPendingSubjectTypeGuard(i, mask)) {
				continue;
			}
			filtered &= ~bit(i);
		}
		return filtered == 0L ? candidates : filtered;
	}

	private boolean introducesPendingSubjectTypeGuard(int factorIndex, long mask) {
		long introducedVars = bindingVarMasks[factorIndex] & ~boundVariableMask(mask);
		return introducedVars != 0L && introducedVarsHasPendingSubjectTypeGuard(factorIndex, mask, introducedVars);
	}

	private SketchBasedJoinEstimator.JoinStepEstimate estimateTransition(long mask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate, int candidate) {
		SketchBasedJoinEstimator.TuplePlanEstimate candidateEstimate = factors.get(candidate).estimate();
		return estimator.estimateJoinStepForJoinOrdering(prefixEstimate, candidateEstimate, sketchIntersectionCache);
	}

	private SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate(long mask, int candidate,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate,
			SketchBasedJoinEstimator.JoinStepEstimate step) {
		SketchBasedJoinEstimator.TuplePlanEstimate estimate = estimator.joinedPlanEstimate(step);
		double outputCap = noNewBindingsDirectLookupOutputCap(mask, candidate, prefixEstimate);
		if (isFiniteNonNegative(outputCap) && estimate.outputRows() > outputCap) {
			return estimator.withOutputRowsForJoinOrdering(estimate, outputCap);
		}
		return estimate;
	}

	private double noNewBindingsDirectLookupOutputCap(long mask, int candidate,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (prefixEstimate == null || !isFiniteNonNegative(prefixEstimate.outputRows())) {
			return Double.NaN;
		}
		long currentlyBoundVarMask = boundVariableMask(mask);
		if ((runtimeVarMasks[candidate] & ~currentlyBoundVarMask) != 0L) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShape(candidate, mask, currentlyBoundVarMask);
		if (!isExactStatementDirectLookup(accessShape)) {
			return Double.NaN;
		}
		double accessRows = accessShape.estimateAccessRows(accessShape.lookupBoundComponentMask());
		double rowsPerInvocation = isFiniteNonNegative(accessRows) ? Math.max(1.0d, accessRows) : 1.0d;
		double cap = prefixEstimate.outputRows() * rowsPerInvocation;
		return isFiniteNonNegative(cap) ? cap : Double.NaN;
	}

	private boolean isExactStatementDirectLookup(SketchBasedJoinEstimator.AccessShape accessShape) {
		if (accessShape == null) {
			return false;
		}
		int exactStatementMask = componentBit(SketchBasedJoinEstimator.Component.S)
				| componentBit(SketchBasedJoinEstimator.Component.P)
				| componentBit(SketchBasedJoinEstimator.Component.O);
		int lookupBoundComponentMask = accessShape.lookupBoundComponentMask();
		return (lookupBoundComponentMask & exactStatementMask) == exactStatementMask
				&& accessShape.isDirectLookup(lookupBoundComponentMask);
	}

	private int componentBit(SketchBasedJoinEstimator.Component component) {
		return 1 << component.ordinal();
	}

	private String connectionReason(long mask, int candidateIndex) {
		long sharedVariableMask = sharedVariableMask(mask, candidateIndex);
		Set<String> sharedVariables = variableNames(sharedVariableMask);
		if (!sharedVariables.isEmpty()) {
			return sharedVariables.size() == 1 ? sharedVariables.iterator().next() : "shared:" + sharedVariables;
		}
		String filterConnection = deferredFilterConnection(mask, candidateIndex);
		if (filterConnection != null) {
			return filterConnection;
		}
		return null;
	}

	private boolean hasConnection(long mask, int candidateIndex) {
		if (sharedVariableMask(mask, candidateIndex) != 0L) {
			return true;
		}
		return deferredFilterConnection(mask, candidateIndex) != null;
	}

	private Set<String> sharedVariables(long mask, int candidateIndex) {
		return variableNames(sharedVariableMask(mask, candidateIndex));
	}

	private long sharedVariableMask(long mask, int candidateIndex) {
		return boundVariableMask(mask) & connectivityVarMasks[candidateIndex];
	}

	private String deferredFilterConnection(long mask, int candidateIndex) {
		if (deferredFilters.isEmpty()) {
			return null;
		}
		long prefixVars = boundVariableMask(mask);
		long candidateVars = bindingVarMasks[candidateIndex];
		long combinedVars = prefixVars | candidateVars;
		for (int i = 0; i < deferredFilters.size(); i++) {
			if (deferredFilterOrderingWeight(deferredFilters.get(i)) <= 0.0d) {
				continue;
			}
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if ((prefixVars & requiredVars) == requiredVars || (combinedVars & requiredVars) != requiredVars
					|| (requiredVars & prefixVars) == 0L || (requiredVars & candidateVars) == 0L) {
				continue;
			}
			return "filter:" + deferredFilters.get(i).getDebugLabel();
		}
		return null;
	}

	private boolean intersects(Set<String> left, Set<String> right) {
		for (String value : left) {
			if (right.contains(value)) {
				return true;
			}
		}
		return false;
	}

	private Set<String> variables(long mask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			Set<String> variables = variablesByState[stateIndex];
			if (variables == null) {
				variables = variableNames(variablesMask(mask));
				variablesByState[stateIndex] = variables;
			}
			return variables;
		}
		return variablesMemo.computeIfAbsent(mask, ignored -> variableNames(variablesMask(mask)));
	}

	private long variablesMask(long mask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			long variables = variablesMaskByState[stateIndex];
			if (variables == UNCOMPUTED_MASK) {
				variables = computeVariablesMask(mask);
				variablesMaskByState[stateIndex] = variables;
			}
			return variables;
		}
		return variablesMaskMemo.computeIfAbsent(mask, this::computeVariablesMask);
	}

	private long computeVariablesMask(long mask) {
		long variables = 0L;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(mask, i)) {
				variables |= joinVarMasks[i];
			}
		}
		return variables;
	}

	private Set<String> boundVariables(long mask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			Set<String> variables = boundVariablesByState[stateIndex];
			if (variables == null) {
				variables = variableNames(boundVariableMask(mask));
				boundVariablesByState[stateIndex] = variables;
			}
			return variables;
		}
		return boundVariablesMemo.computeIfAbsent(mask, ignored -> variableNames(boundVariableMask(mask)));
	}

	private long boundVariableMask(long mask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			long bound = boundVariableMaskByState[stateIndex];
			if (bound == UNCOMPUTED_MASK) {
				bound = computeBoundVariableMask(mask);
				boundVariableMaskByState[stateIndex] = bound;
			}
			return bound;
		}
		return boundVariableMaskMemo.computeIfAbsent(mask, this::computeBoundVariableMask);
	}

	private long computeBoundVariableMask(long mask) {
		long bound = initiallyBoundVarMask;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(mask, i)) {
				bound |= bindingVarMasks[i];
			}
		}
		return bound;
	}

	private Set<String> variableNames(long variableMask) {
		if (variableMask == 0L) {
			return Set.of();
		}
		return new VariableMaskSet(variableMask);
	}

	private final class VariableMaskSet extends AbstractSet<String> {
		private final long variableMask;
		private final int size;

		private VariableMaskSet(long variableMask) {
			this.variableMask = variableMask;
			this.size = Long.bitCount(variableMask);
		}

		@Override
		public Iterator<String> iterator() {
			return new Iterator<>() {
				private long remaining = variableMask;

				@Override
				public boolean hasNext() {
					return remaining != 0L;
				}

				@Override
				public String next() {
					if (remaining == 0L) {
						throw new java.util.NoSuchElementException();
					}
					int bit = Long.numberOfTrailingZeros(remaining);
					remaining &= remaining - 1L;
					return variableNames[bit];
				}
			};
		}

		@Override
		public boolean contains(Object value) {
			if (!(value instanceof String)) {
				return false;
			}
			for (int i = 0; i < variableNames.length; i++) {
				if (((variableMask & (1L << i)) != 0L) && value.equals(variableNames[i])) {
					return true;
				}
			}
			return false;
		}

		@Override
		public int size() {
			return size;
		}
	}

	private SketchBasedJoinEstimator.AccessShape accessShape(int factorIndex, long mask,
			long currentlyBoundVarMask) {
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			SketchBasedJoinEstimator.AccessShape[] shapes = accessShapeByState[stateIndex];
			boolean[] loaded = accessShapeLoadedByState[stateIndex];
			if (shapes == null) {
				shapes = new SketchBasedJoinEstimator.AccessShape[factors.size()];
				accessShapeByState[stateIndex] = shapes;
				loaded = new boolean[factors.size()];
				accessShapeLoadedByState[stateIndex] = loaded;
			}
			if (!loaded[factorIndex]) {
				shapes[factorIndex] = estimator.accessShapeForJoinOrdering(factors.get(factorIndex).tupleExpr(),
						variableNames, currentlyBoundVarMask);
				loaded[factorIndex] = true;
			}
			return shapes[factorIndex];
		}
		AccessShapeKey key = new AccessShapeKey(mask, factorIndex);
		return accessShapeMemo.computeIfAbsent(key,
				ignored -> estimator.accessShapeForJoinOrdering(factors.get(factorIndex).tupleExpr(),
						variableNames, currentlyBoundVarMask));
	}

	private int stateMemoIndex(long mask) {
		return stateMemoSize > 0 && mask >= 0L && mask < stateMemoSize ? (int) mask : -1;
	}

	private double adjustedWorkRows(int factorIndex, long mask, long currentlyBoundVarMask,
			double defaultWorkRows) {
		SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
		return adjustedWorkRows(accessShape, defaultWorkRows);
	}

	private double adjustedWorkRows(SketchBasedJoinEstimator.AccessShape accessShape, double defaultWorkRows) {
		double adjustedWorkRows = workAdjuster.adjustedWorkRows(accessShape, defaultWorkRows);
		if (!(Double.isFinite(adjustedWorkRows) && adjustedWorkRows > 0.0d)) {
			return defaultWorkRows;
		}
		return adjustedWorkRows;
	}

	private SketchBasedJoinEstimator.TuplePlanEstimate conditionedFactorEstimate(int factorIndex,
			long currentlyBoundVarMask) {
		SketchBasedJoinEstimator.TuplePlanEstimate estimate = estimator.conditionedFactorEstimateForJoinOrdering(
				factors.get(factorIndex).tupleExpr(), variableNames, currentlyBoundVarMask);
		return estimate == null ? factors.get(factorIndex).estimate() : estimate;
	}

	private FactorPhysicalEstimate factorPhysicalEstimate(int factorIndex, long mask, long currentlyBoundVarMask,
			double defaultFactorRows, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		double factorRows = defaultFactorRows;
		double accessWorkRows = Double.NaN;
		boolean physicalComparable = false;
		int missingLookupComponents = 0;
		int lookupComponents = 0;
		int lookupComponentMask = 0;
		boolean directLookup = false;
		double accessRowsBeforeFilter = Double.NaN;
		JoinFactorCostModel.FactorCostEstimate factorCostEstimate = factorCostEstimate(factorIndex, mask,
				currentlyBoundVarMask, prefixEstimate);
		if (factorCostEstimate != null) {
			if (isFiniteNonNegative(factorCostEstimate.getOutputRows())) {
				factorRows = factorCostEstimate.getOutputRows();
			}
			if (isFiniteNonNegative(factorCostEstimate.getWorkRows())) {
				accessWorkRows = factorCostEstimate.getWorkRows();
			}
			physicalComparable = factorCostEstimate.getStringMetrics()
					.containsKey(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE);
			if (physicalComparable) {
				directLookup = "directLookup".equals(
						factorCostEstimate.getStringMetrics().get(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE));
				missingLookupComponents = componentCount(
						factorCostEstimate.getStringMetrics()
								.get(TelemetryMetricNames.PLANNED_MISSING_LOOKUP_COMPONENTS));
				String plannedLookupComponents = factorCostEstimate.getStringMetrics()
						.get(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS);
				lookupComponents = componentCount(plannedLookupComponents);
				lookupComponentMask = componentMask(plannedLookupComponents);
				accessRowsBeforeFilter = factorCostEstimate.getDoubleMetrics()
						.getOrDefault(TelemetryMetricNames.PLANNED_ACCESS_ROWS, Double.NaN);
			}
		}
		if (!isFiniteNonNegative(accessWorkRows)) {
			accessWorkRows = factorAccessWorkRows(factorIndex, mask, currentlyBoundVarMask, factorRows,
					prefixEstimate);
		} else if (!costModelChargedRepeatedInvocations(factorCostEstimate)
				&& shouldAmplifyRepeatedLookup(factorIndex, mask, currentlyBoundVarMask, prefixEstimate)) {
			SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
			double perInvocationWorkRows = accessWorkRows;
			if (isFiniteNonNegative(accessRowsBeforeFilter)) {
				perInvocationWorkRows = Math.max(perInvocationWorkRows, accessRowsBeforeFilter);
			}
			accessWorkRows = repeatedLookupWorkRows(prefixEstimate, perInvocationWorkRows, accessShape,
					lookupComponentMask);
		}
		accessWorkRows = applyPendingSmallBindingAssignmentDomainWork(factorIndex, mask, currentlyBoundVarMask,
				accessWorkRows, prefixEstimate);
		accessWorkRows = applyDisconnectedSmallBindingAssignmentExpansionWork(factorIndex, mask, currentlyBoundVarMask,
				accessWorkRows, prefixEstimate);
		accessWorkRows = applyPendingSubjectTypeGuardDomainWork(factorIndex, mask, currentlyBoundVarMask,
				accessWorkRows, prefixEstimate, directLookup);
		accessWorkRows = applyPendingBoundSubjectTypeGuardWork(factorIndex, mask, currentlyBoundVarMask,
				accessWorkRows, prefixEstimate);
		accessWorkRows = applyDisconnectedCartesianExpansionWork(factorIndex, mask, accessWorkRows, prefixEstimate);
		if (!isFiniteNonNegative(factorRows)) {
			factorRows = defaultFactorRows;
		}
		return new FactorPhysicalEstimate(accessWorkRows, factorRows, physicalComparable, missingLookupComponents,
				lookupComponents, lookupComponentMask, directLookup, accessRowsBeforeFilter, factorCostEstimate);
	}

	private JoinFactorCostModel.FactorCostEstimate factorCostEstimate(int factorIndex, long mask,
			long currentlyBoundVarMask, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (factorCostModel == null) {
			return null;
		}
		if (prefixEstimate != null) {
			return estimateFactorCostUncached(factorIndex, mask, currentlyBoundVarMask, prefixEstimate);
		}
		int stateIndex = stateMemoIndex(mask);
		if (stateIndex >= 0) {
			JoinFactorCostModel.FactorCostEstimate[] estimates = factorCostByState[stateIndex];
			boolean[] loaded = factorCostLoadedByState[stateIndex];
			if (estimates == null) {
				estimates = new JoinFactorCostModel.FactorCostEstimate[factors.size()];
				factorCostByState[stateIndex] = estimates;
				loaded = new boolean[factors.size()];
				factorCostLoadedByState[stateIndex] = loaded;
			}
			if (!loaded[factorIndex]) {
				estimates[factorIndex] = estimateFactorCostUncached(factorIndex, mask, currentlyBoundVarMask, null);
				loaded[factorIndex] = true;
			}
			return estimates[factorIndex];
		}
		FactorCostKey key = new FactorCostKey(mask, factorIndex);
		return factorCostMemo.computeIfAbsent(key,
				ignored -> Optional.ofNullable(estimateFactorCostUncached(factorIndex, mask, currentlyBoundVarMask,
						null)))
				.orElse(null);
	}

	private JoinFactorCostModel.FactorCostEstimate estimateFactorCostUncached(int factorIndex,
			long mask, long currentlyBoundVarMask, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		Set<String> currentlyBoundVars = variableNames(currentlyBoundVarMask);
		double outerPrefixRows = effectiveInvocationRows(mask, prefixEstimate);
		double distinctLookupBindings = Double.NaN;
		if (prefixEstimate != null) {
			SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
			distinctLookupBindings = distinctLookupBindings(prefixEstimate, accessShape,
					accessShape == null ? 0 : accessShape.lookupBoundComponentMask());
		}
		JoinFactorCostModel.CostContext context = JoinFactorCostModel.CostContext.of(currentlyBoundVars,
				outerPrefixRows, distinctLookupBindings, prefixEstimate != null);
		Optional<JoinFactorCostModel.FactorCostEstimate> estimate = factorCostModel
				.estimateFactorCost(factors.get(factorIndex).tupleExpr(), context);
		return estimate.orElse(null);
	}

	private boolean shouldAmplifyRepeatedLookup(int factorIndex, long mask, long currentlyBoundVarMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (mask == 0L || prefixEstimate == null) {
			return false;
		}
		SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
		return accessShape != null && accessShape.joinBoundComponentMask() != 0;
	}

	private boolean costModelChargedRepeatedInvocations(JoinFactorCostModel.FactorCostEstimate factorCostEstimate) {
		return factorCostEstimate != null
				&& factorCostEstimate.getDoubleMetrics().containsKey("plannedRepeatedInvocations");
	}

	private double factorAccessWorkRows(int factorIndex, long mask, long currentlyBoundVarMask,
			double factorRows, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
		double accessWorkRows = adjustedWorkRows(accessShape, factorRows);
		if (!shouldAmplifyRepeatedLookup(factorIndex, mask, currentlyBoundVarMask, prefixEstimate)) {
			return accessWorkRows;
		}
		return repeatedLookupWorkRows(prefixEstimate, accessWorkRows, accessShape,
				accessShape.lookupBoundComponentMask());
	}

	private double adjustedTransitionWorkRows(int factorIndex, long mask, long currentlyBoundVarMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate, double defaultWorkRows) {
		SketchBasedJoinEstimator.AccessShape accessShape = accessShape(factorIndex, mask, currentlyBoundVarMask);
		double adjustedWorkRows = adjustedWorkRows(accessShape, defaultWorkRows);
		if (accessShape == null || accessShape.joinBoundComponentMask() == 0) {
			return adjustedWorkRows;
		}

		double prefixRows = prefixEstimate.outputRows();
		if (!Double.isFinite(prefixRows) || prefixRows <= 1.0d) {
			return adjustedWorkRows;
		}

		double repeatedLookupWorkRows = repeatedLookupWorkRows(prefixEstimate, adjustedWorkRows, accessShape,
				accessShape.lookupBoundComponentMask());
		if (!Double.isFinite(repeatedLookupWorkRows) || repeatedLookupWorkRows <= adjustedWorkRows) {
			return adjustedWorkRows;
		}
		return Double.isFinite(defaultWorkRows) && defaultWorkRows >= 0.0d
				? Math.min(defaultWorkRows, repeatedLookupWorkRows)
				: repeatedLookupWorkRows;
	}

	private double repeatedLookupWorkRows(SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate,
			double lookupWorkRows, SketchBasedJoinEstimator.AccessShape accessShape, int lookupComponentMask) {
		double prefixRows = prefixEstimate.outputRows();
		if (!Double.isFinite(prefixRows) || prefixRows <= 1.0d) {
			return lookupWorkRows;
		}
		double repeatedLookupWorkRows = lookupWorkRows * prefixRows;
		return Double.isFinite(repeatedLookupWorkRows) && repeatedLookupWorkRows > lookupWorkRows
				? Math.max(prefixRows, repeatedLookupWorkRows)
				: lookupWorkRows;
	}

	private double distinctLookupBindings(SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate,
			SketchBasedJoinEstimator.AccessShape accessShape, int lookupComponentMask) {
		if (accessShape == null) {
			return prefixEstimate.outputRows();
		}
		Set<String> lookupVarNames = new HashSet<>();
		int effectiveLookupComponentMask = lookupComponentMask == 0
				? accessShape.lookupBoundComponentMask()
				: lookupComponentMask;
		for (SketchBasedJoinEstimator.Component component : SketchBasedJoinEstimator.Component.values()) {
			int componentBit = 1 << component.ordinal();
			if ((effectiveLookupComponentMask & componentBit) == 0) {
				continue;
			}
			String varName = accessShape.joinBoundVarName(component);
			if (isPlannerVariableName(varName)) {
				lookupVarNames.add(varName);
			}
		}
		return prefixEstimate.distinctBindings(lookupVarNames);
	}

	private double applyPendingSmallBindingAssignmentDomainWork(int factorIndex, long mask, long currentlyBoundVarMask,
			double accessWorkRows, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (!isFiniteNonNegative(accessWorkRows) || isBindingSetAssignment(factorIndex)) {
			return accessWorkRows;
		}
		double pendingDomainRows = pendingSmallBindingAssignmentRows(factorIndex, mask, currentlyBoundVarMask);
		if (!(pendingDomainRows > 0.0d)) {
			return accessWorkRows;
		}
		double adjustedWorkRows = accessWorkRows + pendingDomainRows * effectiveInvocationRows(mask, prefixEstimate);
		return isFiniteNonNegative(adjustedWorkRows) && adjustedWorkRows > accessWorkRows
				? adjustedWorkRows
				: accessWorkRows;
	}

	private double pendingSmallBindingAssignmentRows(int factorIndex, long mask, long currentlyBoundVarMask) {
		long introducedVars = bindingVarMasks[factorIndex] & ~currentlyBoundVarMask;
		if (introducedVars == 0L) {
			return 0.0d;
		}
		double rows = 0.0d;
		for (int i = 0; i < factors.size(); i++) {
			if (i == factorIndex || contains(mask, i) || !isSmallBindingSetAssignment(i)
					|| (bindingVarMasks[i] & introducedVars) == 0L) {
				continue;
			}
			double assignmentRows = factors.get(i).estimate().outputRows();
			if (isFiniteNonNegative(assignmentRows)) {
				rows += assignmentRows;
			}
		}
		return rows;
	}

	private double applyDisconnectedSmallBindingAssignmentExpansionWork(int factorIndex, long mask,
			long currentlyBoundVarMask, double accessWorkRows,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (!isFiniteNonNegative(accessWorkRows) || !isSmallBindingSetAssignment(factorIndex)) {
			return accessWorkRows;
		}
		double domainRows = factors.get(factorIndex).estimate().outputRows();
		if (!(domainRows > 1.0d)) {
			return accessWorkRows;
		}
		double prefixRows = effectiveInvocationRows(mask, prefixEstimate);
		double expansionWorkRows = (domainRows - 1.0d) * prefixRows;
		if (!smallBindingAssignmentConstrainsRemainingFactor(factorIndex, mask, currentlyBoundVarMask)) {
			double futureWorkRows = cheapestRemainingNonAssignmentAccessWork(factorIndex, mask, currentlyBoundVarMask,
					prefixEstimate);
			if (futureWorkRows > 0.0d) {
				expansionWorkRows += (domainRows - 1.0d) * futureWorkRows;
			}
		}
		double adjustedWorkRows = accessWorkRows + expansionWorkRows;
		return isFiniteNonNegative(adjustedWorkRows) && adjustedWorkRows > accessWorkRows
				? adjustedWorkRows
				: accessWorkRows;
	}

	private double finiteBindingAssignmentPrefixRows(long mask) {
		double rows = 1.0d;
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(mask, i) || !isSmallBindingSetAssignment(i)) {
				continue;
			}
			double assignmentRows = factors.get(i).estimate().outputRows();
			if (!isFiniteNonNegative(assignmentRows) || assignmentRows <= 1.0d) {
				continue;
			}
			rows *= assignmentRows;
			if (!Double.isFinite(rows)) {
				return Double.MAX_VALUE;
			}
		}
		return rows;
	}

	private double effectiveInvocationRows(long mask, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		double rows = prefixEstimate == null ? 1.0d : prefixEstimate.outputRows();
		if (!Double.isFinite(rows) || rows <= 0.0d) {
			rows = 1.0d;
		}
		double prefixRows = initialPrefixRows * finiteBindingAssignmentPrefixRows(mask);
		if (Double.isFinite(prefixRows) && prefixRows > rows) {
			rows = prefixRows;
		}
		return rows;
	}

	private boolean smallBindingAssignmentConstrainsRemainingFactor(int factorIndex, long mask,
			long currentlyBoundVarMask) {
		long assignmentIntroducedVars = bindingVarMasks[factorIndex] & ~currentlyBoundVarMask;
		if (assignmentIntroducedVars == 0L) {
			return false;
		}
		for (int i = 0; i < factors.size(); i++) {
			if (i != factorIndex && !contains(mask, i) && !isBindingSetAssignment(i)
					&& (bindingVarMasks[i] & assignmentIntroducedVars) != 0L) {
				return true;
			}
		}
		return false;
	}

	private double cheapestRemainingNonAssignmentAccessWork(int factorIndex, long mask, long currentlyBoundVarMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		long nextMask = mask | bit(factorIndex);
		double cheapestWorkRows = Double.POSITIVE_INFINITY;
		for (int i = 0; i < factors.size(); i++) {
			if (i == factorIndex || contains(nextMask, i) || isBindingSetAssignment(i)) {
				continue;
			}
			double workRows = rawFactorAccessWorkRows(i, nextMask, currentlyBoundVarMask, prefixEstimate);
			if (isFiniteNonNegative(workRows) && workRows < cheapestWorkRows) {
				cheapestWorkRows = workRows;
			}
		}
		return Double.isFinite(cheapestWorkRows) ? cheapestWorkRows : 0.0d;
	}

	private double rawFactorAccessWorkRows(int factorIndex, long mask, long currentlyBoundVarMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		JoinFactorCostModel.FactorCostEstimate factorCostEstimate = factorCostEstimate(factorIndex, mask,
				currentlyBoundVarMask, prefixEstimate);
		if (factorCostEstimate != null && isFiniteNonNegative(factorCostEstimate.getWorkRows())) {
			return factorCostEstimate.getWorkRows();
		}
		return factorAccessWorkRows(factorIndex, mask, currentlyBoundVarMask,
				factors.get(factorIndex).estimate().outputRows(), prefixEstimate);
	}

	private double applyPendingSubjectTypeGuardDomainWork(int factorIndex, long mask, long currentlyBoundVarMask,
			double accessWorkRows, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate, boolean directLookup) {
		if (!isFiniteNonNegative(accessWorkRows) || directLookup || isSubjectTypeGuard(factorIndex)
				|| (bindingVarMasks[factorIndex] & currentlyBoundVarMask) == 0L) {
			return accessWorkRows;
		}
		double pendingDomainRows = pendingSubjectTypeGuardRows(factorIndex, mask, currentlyBoundVarMask);
		if (!(pendingDomainRows > 0.0d)) {
			return accessWorkRows;
		}
		double prefixRows = effectiveInvocationRows(mask, prefixEstimate);
		double guardedDomainWorkRows = prefixRows * pendingDomainRows;
		double adjustedWorkRows = accessWorkRows + guardedDomainWorkRows;
		return isFiniteNonNegative(adjustedWorkRows) && adjustedWorkRows > accessWorkRows
				? adjustedWorkRows
				: accessWorkRows;
	}

	private double applyPendingBoundSubjectTypeGuardWork(int factorIndex, long mask, long currentlyBoundVarMask,
			double accessWorkRows, SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (!isFiniteNonNegative(accessWorkRows) || isSubjectTypeGuard(factorIndex)) {
			return accessWorkRows;
		}
		double pendingGuardWorkRows = pendingBoundSubjectTypeGuardWorkRows(factorIndex, mask, currentlyBoundVarMask,
				prefixEstimate);
		if (!(pendingGuardWorkRows > 0.0d)) {
			return accessWorkRows;
		}
		double adjustedWorkRows = accessWorkRows + pendingGuardWorkRows;
		return isFiniteNonNegative(adjustedWorkRows) && adjustedWorkRows > accessWorkRows
				? adjustedWorkRows
				: accessWorkRows;
	}

	private double pendingBoundSubjectTypeGuardWorkRows(int factorIndex, long mask, long currentlyBoundVarMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		long boundSubjectVars = subjectVarMask(factorIndex) & currentlyBoundVarMask;
		if (boundSubjectVars == 0L) {
			return 0.0d;
		}
		double rows = 0.0d;
		for (int i = 0; i < factors.size(); i++) {
			if (i == factorIndex || contains(mask, i) || !isSubjectTypeGuard(i)
					|| (subjectVarMask(i) & boundSubjectVars) == 0L) {
				continue;
			}
			double guardWorkRows = rawFactorAccessWorkRows(i, mask, currentlyBoundVarMask, prefixEstimate);
			if (isFiniteNonNegative(guardWorkRows)) {
				rows += guardWorkRows;
			}
		}
		return rows;
	}

	private double applyDisconnectedCartesianExpansionWork(int factorIndex, long mask, double accessWorkRows,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate) {
		if (mask == 0L || prefixEstimate == null || !isFiniteNonNegative(accessWorkRows)
				|| isSmallBindingSetAssignment(factorIndex) || runtimeVarMasks[factorIndex] == 0L
				|| hasConnection(mask, factorIndex)) {
			return accessWorkRows;
		}
		double prefixRows = effectiveInvocationRows(mask, prefixEstimate);
		if (!(Double.isFinite(prefixRows) && prefixRows > 1.0d)) {
			return accessWorkRows;
		}
		double repeatedWorkRows = prefixRows * accessWorkRows;
		return isFiniteNonNegative(repeatedWorkRows) && repeatedWorkRows > accessWorkRows
				? repeatedWorkRows
				: accessWorkRows;
	}

	private double pendingSubjectTypeGuardRows(int factorIndex, long mask, long currentlyBoundVarMask) {
		long introducedVars = bindingVarMasks[factorIndex] & ~currentlyBoundVarMask;
		if (introducedVars == 0L) {
			return 0.0d;
		}
		double rows = 0.0d;
		for (int i = 0; i < factors.size(); i++) {
			if (i == factorIndex || contains(mask, i) || !isSubjectTypeGuard(i)
					|| (subjectVarMask(i) & introducedVars) == 0L) {
				continue;
			}
			double typeRows = factors.get(i).estimate().outputRows();
			if (isFiniteNonNegative(typeRows)) {
				rows += typeRows;
			}
		}
		return rows;
	}

	private double stepWorkRows(long previousMask, long nextMask, double accessWorkRows, double rowsEnteringFilter,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		accessWorkRows = lookupFilterAdjustedAccessWorkRows(previousMask, nextMask, accessWorkRows);
		double filterInvocationRows = rowsEnteringFilter;
		if (isFiniteNonNegative(accessWorkRows)) {
			filterInvocationRows = Math.max(filterInvocationRows, accessWorkRows);
		}
		double filterWorkRows = newlyUnlockedFilterWorkRows(previousMask, nextMask, filterInvocationRows,
				rowsEnteringEstimate);
		double outputWorkRows = outputWorkRows(rowsEnteringFilter);
		double totalWorkRows = accessWorkRows + filterWorkRows + outputWorkRows;
		if (Double.isFinite(totalWorkRows) && totalWorkRows >= 0.0d) {
			return totalWorkRows;
		}
		return accessWorkRows;
	}

	private double rowsProcessedByStep(int factorIndex, long previousMask,
			SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate, double estimatedRows) {
		if (!isSmallBindingSetAssignment(factorIndex)) {
			return estimatedRows;
		}
		double domainRows = factors.get(factorIndex).estimate().outputRows();
		if (!isFiniteNonNegative(domainRows)) {
			return estimatedRows;
		}
		double prefixRows = effectiveInvocationRows(previousMask, prefixEstimate);
		double expandedRows = prefixRows * Math.max(1.0d, domainRows);
		if (!isFiniteNonNegative(expandedRows)) {
			return estimatedRows;
		}
		if (!isFiniteNonNegative(estimatedRows)) {
			return expandedRows;
		}
		return Math.max(estimatedRows, expandedRows);
	}

	private static double outputWorkRows(double rowsEnteringFilter) {
		return isFiniteNonNegative(rowsEnteringFilter) ? rowsEnteringFilter : 0.0d;
	}

	private double lookupFilterAdjustedAccessWorkRows(long previousMask, long nextMask, double accessWorkRows) {
		if (!isFiniteNonNegative(accessWorkRows)) {
			return accessWorkRows;
		}
		double passRatio = newlyUnlockedLookupFilterPassRatio(previousMask, nextMask);
		if (!(Double.isFinite(passRatio) && passRatio >= 0.0d && passRatio < 1.0d)) {
			return accessWorkRows;
		}
		double adjustedWorkRows = Math.max(1.0d, accessWorkRows * passRatio);
		return isFiniteNonNegative(adjustedWorkRows) && adjustedWorkRows < accessWorkRows
				? adjustedWorkRows
				: accessWorkRows;
	}

	private double newlyUnlockedLookupFilterPassRatio(long previousMask, long nextMask) {
		if (deferredFilters.isEmpty()) {
			return 1.0d;
		}
		long previousBound = effectiveFilterBoundVariableMask(previousMask);
		long nextBound = effectiveFilterBoundVariableMask(nextMask);
		long nextActualBound = boundVariableMask(nextMask);
		double passRatio = 1.0d;
		boolean found = false;
		for (int i = 0; i < deferredFilters.size(); i++) {
			JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(i);
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if (!filter.isLookupCompatible()
					|| !canApplyPassRatioToLookupAccess(filter)
					|| (previousBound & requiredVars) == requiredVars
					|| (nextBound & requiredVars) != requiredVars
					|| !hasFiniteLookupDomain(requiredVars, nextActualBound, filter)) {
				continue;
			}
			double filterPassRatio = filter.getEstimatedPassRatio();
			if (Double.isFinite(filterPassRatio) && filterPassRatio >= 0.0d && filterPassRatio <= 1.0d) {
				passRatio *= filterPassRatio;
				found = true;
			}
		}
		return found ? passRatio : 1.0d;
	}

	private boolean hasFiniteLookupDomain(long requiredVars, long actualBound,
			JoinOrderPlanner.FilterConstraint filter) {
		long missingActual = requiredVars & ~actualBound;
		if (missingActual == 0L) {
			return filter.getRequiredVars().size() == 1;
		}
		for (int i = 0; i < factors.size(); i++) {
			if (isSmallBindingSetAssignment(i) && (bindingVarMasks[i] & missingActual) != 0L) {
				missingActual &= ~bindingVarMasks[i];
			}
		}
		return missingActual == 0L;
	}

	private double newlyUnlockedFilterWorkRows(long previousMask, long nextMask, double rowsEnteringFilter,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		if (deferredFilters.isEmpty() || !(Double.isFinite(rowsEnteringFilter) && rowsEnteringFilter > 0.0d)) {
			return 0.0d;
		}
		long previousBound = boundVariableMask(previousMask);
		long nextBound = boundVariableMask(nextMask);
		double workRows = 0.0d;
		for (int i = 0; i < deferredFilters.size(); i++) {
			JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(i);
			if (!isDeferredFilterNewlyPlaced(i, previousMask, nextMask, previousBound, nextBound)
					|| filter.getConditionCost() <= JoinOrderPlanner.FILTER_COST_CHEAP) {
				continue;
			}
			workRows += nestedFilterWorkRows(filter, rowsEnteringFilter, rowsEnteringEstimate, nextBound);
		}
		return Double.isFinite(workRows) && workRows >= 0.0d ? workRows : 0.0d;
	}

	private double nestedFilterWorkRows(JoinOrderPlanner.FilterConstraint filter, double rowsEnteringFilter,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate, long nextBound) {
		if (filter.getNestedTupleExpression().isEmpty()) {
			return rowsEnteringFilter;
		}
		double invocations = rowsEnteringFilter;
		if (rowsEnteringEstimate != null && isFiniteNonNegative(rowsEnteringEstimate.outputRows())) {
			invocations = Math.max(invocations, rowsEnteringEstimate.outputRows());
		}
		invocations = Math.max(1.0d, invocations);
		double perInvocationWorkRows = nestedTupleWorkRows(filter.getNestedTupleExpression().get(),
				variableNames(nextBound));
		if (!isFiniteNonNegative(perInvocationWorkRows)) {
			return rowsEnteringFilter;
		}
		double repeatedWorkRows = invocations * Math.max(1.0d, perInvocationWorkRows);
		if (!isFiniteNonNegative(repeatedWorkRows)) {
			return rowsEnteringFilter;
		}
		return Math.max(rowsEnteringFilter, repeatedWorkRows);
	}

	private double nestedTupleWorkRows(TupleExpr nestedTupleExpression, Set<String> boundVars) {
		if (nestedTupleExpression == null) {
			return Double.NaN;
		}
		if (factorCostModel instanceof JoinOrderPlanner planner) {
			List<TupleExpr> flattened = new ArrayList<>();
			flattenJoinFactors(nestedTupleExpression, flattened);
			if (!flattened.isEmpty()) {
				Optional<JoinOrderPlanner.JoinOrderPlan> plan = planner.estimateJoinOrder(flattened, boundVars,
						JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, List.of());
				if (plan.isPresent() && isFiniteNonNegative(plan.get().getEstimatedTotalWork())) {
					return plan.get().getEstimatedTotalWork();
				}
			}
		}
		if (factorCostModel != null) {
			Optional<JoinFactorCostModel.FactorCostEstimate> estimate = factorCostModel.estimateFactorCost(
					nestedTupleExpression,
					JoinFactorCostModel.CostContext.of(boundVars, 1.0d, Double.NaN, true));
			if (estimate.isPresent() && isFiniteNonNegative(estimate.get().getWorkRows())) {
				return estimate.get().getWorkRows();
			}
		}
		double rows = estimator.factorOutputRowsForJoinOrdering(nestedTupleExpression, boundVars);
		return isFiniteNonNegative(rows) ? rows : Double.NaN;
	}

	private double nestedExistsPassRatio(JoinOrderPlanner.FilterConstraint filter,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		if (!filter.hasNestedTupleExpression() || filter.isNotExists() || rowsEnteringEstimate == null
				|| !isFiniteNonNegative(rowsEnteringEstimate.outputRows())
				|| rowsEnteringEstimate.outputRows() == 0.0d) {
			return Double.NaN;
		}
		Optional<TupleExpr> nestedTupleExpression = filter.getNestedTupleExpression();
		if (nestedTupleExpression.isEmpty()) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.TuplePlanEstimate nestedEstimate = estimator.planEstimateForJoinOrdering(
				nestedTupleExpression.get(), Set.of());
		if (nestedEstimate == null || !isFiniteNonNegative(nestedEstimate.outputRows())) {
			return Double.NaN;
		}
		SketchBasedJoinEstimator.JoinStepEstimate joinedEstimate = estimator.estimateJoinStepForJoinOrdering(
				rowsEnteringEstimate, nestedEstimate, sketchIntersectionCache);
		double joinedRows = joinedEstimate.outputRows();
		if (!isFiniteNonNegative(joinedRows)) {
			return Double.NaN;
		}
		return Math.min(1.0d, joinedRows / rowsEnteringEstimate.outputRows());
	}

	private void flattenJoinFactors(TupleExpr tupleExpr, List<TupleExpr> factors) {
		if (tupleExpr instanceof Join && !TupleExprs.isVariableScopeChange(tupleExpr)) {
			Join join = (Join) tupleExpr;
			flattenJoinFactors(join.getLeftArg(), factors);
			flattenJoinFactors(join.getRightArg(), factors);
			return;
		}
		factors.add(tupleExpr);
	}

	private boolean isDeferredFilterNewlyPlaced(int filterIndex, long previousMask, long nextMask,
			long previousBound, long nextBound) {
		long requiredVars = deferredFilterRequiredVarMasks[filterIndex];
		if (requiredVars == 0L || (nextBound & requiredVars) != requiredVars) {
			return false;
		}
		JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(filterIndex);
		if (!filter.hasNestedTupleExpression()) {
			return (previousBound & requiredVars) != requiredVars;
		}
		return (previousBound & requiredVars) != requiredVars;
	}

	private boolean isSmallBindingSetAssignment(int factorIndex) {
		PlanFactor factor = factors.get(factorIndex);
		if (!isBindingSetAssignment(factorIndex)) {
			return false;
		}
		double outputRows = factor.estimate().outputRows();
		return Double.isFinite(outputRows) && outputRows >= 0.0d
				&& outputRows <= SMALL_BINDING_SET_ASSIGNMENT_MAX_ROWS;
	}

	private boolean isBindingSetAssignment(int factorIndex) {
		return factors.get(factorIndex).tupleExpr() instanceof BindingSetAssignment;
	}

	private boolean isSubjectTypeGuard(int factorIndex) {
		TupleExpr tupleExpr = factors.get(factorIndex).tupleExpr();
		if (!(tupleExpr instanceof StatementPattern statementPattern)) {
			return false;
		}
		Var predicate = statementPattern.getPredicateVar();
		Var object = statementPattern.getObjectVar();
		return predicate != null && predicate.hasValue()
				&& RDF.TYPE.equals(predicate.getValue())
				&& object != null && object.hasValue()
				&& subjectVarMask(factorIndex) != 0L;
	}

	private long subjectVarMask(int factorIndex) {
		TupleExpr tupleExpr = factors.get(factorIndex).tupleExpr();
		if (!(tupleExpr instanceof StatementPattern statementPattern)) {
			return 0L;
		}
		Var subject = statementPattern.getSubjectVar();
		if (subject == null || subject.hasValue()) {
			return 0L;
		}
		Integer id = variableIds.get(subject.getName());
		return id == null ? 0L : 1L << id.intValue();
	}

	private SketchBasedJoinEstimator.TuplePlanEstimate applyUnlockedFilters(long previousMask, long nextMask,
			SketchBasedJoinEstimator.TuplePlanEstimate estimate) {
		double passRatio = newlyUnlockedFilterPassRatio(previousMask, nextMask, estimate);
		if (passRatio >= 1.0d) {
			return estimate;
		}
		double filteredRows = estimate.outputRows() * passRatio;
		if (!Double.isFinite(filteredRows) || filteredRows < 0.0d) {
			return estimate;
		}
		return estimator.withOutputRowsForJoinOrdering(estimate, filteredRows);
	}

	private double newlyUnlockedFilterPassRatio(long previousMask, long nextMask,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		if (deferredFilters.isEmpty()) {
			return 1.0d;
		}
		if (isDisconnectedCorrelatedSeed(previousMask, nextMask)) {
			return 1.0d;
		}
		long previousBound = effectiveFilterBoundVariableMask(previousMask);
		long nextBound = effectiveFilterBoundVariableMask(nextMask);
		double passRatio = 1.0d;
		boolean found = false;
		for (int i = 0; i < deferredFilters.size(); i++) {
			JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(i);
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if ((previousBound & requiredVars) == requiredVars
					|| (nextBound & requiredVars) != requiredVars) {
				continue;
			}
			double filterPassRatio = nestedExistsPassRatio(filter, rowsEnteringEstimate);
			if (!isValidPassRatio(filterPassRatio)) {
				if (!canApplyPassRatioToOutputRows(filter)) {
					continue;
				}
				filterPassRatio = filter.getEstimatedPassRatio();
			}
			if (Double.isFinite(filterPassRatio) && filterPassRatio >= 0.0d && filterPassRatio <= 1.0d) {
				passRatio *= filterPassRatio;
				found = true;
			}
		}
		return found ? passRatio : 1.0d;
	}

	private long effectiveFilterBoundVariableMask(long mask) {
		long effectiveBound = boundVariableMask(mask);
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(mask, i) && isSmallBindingSetAssignment(i)) {
				effectiveBound |= bindingVarMasks[i];
			}
		}
		return effectiveBound;
	}

	private boolean canApplyPassRatioToOutputRows(JoinOrderPlanner.FilterConstraint filter) {
		return !filter.hasNestedTupleExpression();
	}

	private boolean canApplyPassRatioToLookupAccess(JoinOrderPlanner.FilterConstraint filter) {
		return filter.getConditionCost() <= JoinOrderPlanner.FILTER_COST_CHEAP && !filter.hasNestedTupleExpression();
	}

	private boolean isDisconnectedCorrelatedSeed(long previousMask, long nextMask) {
		return previousMask == 0L
				&& initiallyBoundVarMask != 0L
				&& (boundVariableMask(nextMask) & initiallyBoundVarMask) == 0L
				&& hasFactorConnectedToInitiallyBoundVars();
	}

	private boolean hasFactorConnectedToInitiallyBoundVars() {
		for (long runtimeVarMask : runtimeVarMasks) {
			if ((runtimeVarMask & initiallyBoundVarMask) != 0L) {
				return true;
			}
		}
		return false;
	}

	private int compareBoundGuardOrder(List<Integer> left, List<Integer> right) {
		int size = Math.min(left.size(), right.size());
		long leftMask = 0L;
		long rightMask = 0L;
		long lastIntroducedVars = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.get(i);
			int rightIndex = right.get(i);
			if (leftIndex != rightIndex) {
				boolean leftGuard = isBoundGuardFactor(leftIndex, leftMask);
				boolean rightGuard = isBoundGuardFactor(rightIndex, rightMask);
				if (leftGuard && rightGuard) {
					int subjectTypeGuardComparison = compareSubjectTypeBoundGuardOrder(leftIndex, rightIndex,
							leftMask);
					if (subjectTypeGuardComparison != 0) {
						return subjectTypeGuardComparison;
					}
					int latestSubjectTypeComparison = compareLatestSubjectTypeGuardOrder(leftIndex, rightIndex,
							lastIntroducedVars);
					if (latestSubjectTypeComparison != 0) {
						return latestSubjectTypeComparison;
					}
				}
				if (leftGuard != rightGuard) {
					if (leftGuard && shouldDelaySubjectTypeGuard(leftIndex, rightIndex, leftMask)) {
						return 1;
					}
					if (rightGuard && shouldDelaySubjectTypeGuard(rightIndex, leftIndex, rightMask)) {
						return -1;
					}
					return leftGuard ? -1 : 1;
				}
			}
			long boundBeforeStep = boundVariableMask(leftMask);
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private int compareSubjectTypeBoundGuardExpansionOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long leftMask = 0L;
		long rightMask = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				boolean leftGuard = subjectTypeBoundGuardShouldPrecedeExpansion(leftIndex, rightIndex, leftMask,
						left.physicalStepRanks().get(i), right.physicalStepRanks().get(i));
				boolean rightGuard = subjectTypeBoundGuardShouldPrecedeExpansion(rightIndex, leftIndex, rightMask,
						right.physicalStepRanks().get(i), left.physicalStepRanks().get(i));
				if (leftGuard == rightGuard) {
					return 0;
				}
				return leftGuard ? -1 : 1;
			}
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
		}
		return 0;
	}

	private boolean subjectTypeBoundGuardShouldPrecedeExpansion(int guardIndex, int alternativeIndex,
			long previousMask, PhysicalStepRank guardStep, PhysicalStepRank alternativeStep) {
		return isSubjectTypeGuard(guardIndex)
				&& isBoundGuardFactor(guardIndex, previousMask)
				&& subjectTypeGuardShouldPrecedeBoundFactor(guardIndex, alternativeIndex, previousMask)
				&& stepWorkComparable(guardStep.workRows(), alternativeStep.workRows(),
						BOUND_GUARD_MAX_STEP_WORK_RATIO);
	}

	private int compareSubjectTypeBoundGuardOrder(int leftIndex, int rightIndex, long previousMask) {
		boolean leftSubjectTypeGuard = isSubjectTypeGuard(leftIndex);
		boolean rightSubjectTypeGuard = isSubjectTypeGuard(rightIndex);
		if (leftSubjectTypeGuard == rightSubjectTypeGuard) {
			return 0;
		}
		if (leftSubjectTypeGuard && subjectTypeGuardShouldPrecedeBoundFactor(leftIndex, rightIndex, previousMask)) {
			return -1;
		}
		if (rightSubjectTypeGuard && subjectTypeGuardShouldPrecedeBoundFactor(rightIndex, leftIndex, previousMask)) {
			return 1;
		}
		return 0;
	}

	private boolean subjectTypeGuardShouldPrecedeBoundFactor(int guardIndex, int alternativeIndex, long previousMask) {
		if (isFilteredFactor(alternativeIndex)) {
			return false;
		}
		long previousBound = boundVariableMask(previousMask);
		if ((subjectVarMask(guardIndex) & previousBound) == 0L
				|| (subjectVarMask(guardIndex) & runtimeVarMasks[alternativeIndex]) == 0L) {
			return false;
		}
		long introducedVars = bindingVarMasks[alternativeIndex] & ~previousBound;
		return introducedVars == 0L
				|| !introducedVarsHasPendingSubjectTypeGuard(alternativeIndex, previousMask, introducedVars);
	}

	private int compareLatestSubjectTypeGuardOrder(int leftIndex, int rightIndex, long lastIntroducedVars) {
		if (lastIntroducedVars == 0L || !isSubjectTypeGuard(leftIndex) || !isSubjectTypeGuard(rightIndex)) {
			return 0;
		}
		boolean leftLatest = (subjectVarMask(leftIndex) & lastIntroducedVars) != 0L;
		boolean rightLatest = (subjectVarMask(rightIndex) & lastIntroducedVars) != 0L;
		if (leftLatest == rightLatest) {
			return 0;
		}
		return leftLatest ? -1 : 1;
	}

	private boolean shouldDelaySubjectTypeGuard(int guardIndex, int alternativeIndex, long previousMask) {
		if (!isSubjectTypeGuard(guardIndex) || isBindingSetAssignment(alternativeIndex)) {
			return false;
		}
		long boundBefore = boundVariableMask(previousMask);
		long alternativeRuntimeVars = runtimeVarMasks[alternativeIndex];
		long introducedVars = bindingVarMasks[alternativeIndex] & ~boundBefore;
		return (alternativeRuntimeVars & boundBefore) != 0L
				&& introducedVars != 0L
				&& introducedVarsHasPendingSubjectTypeGuard(alternativeIndex, previousMask, introducedVars);
	}

	private boolean introducedVarsHasPendingSubjectTypeGuard(int alternativeIndex, long previousMask,
			long introducedVars) {
		for (int i = 0; i < factors.size(); i++) {
			if (i == alternativeIndex || contains(previousMask, i) || !isSubjectTypeGuard(i)) {
				continue;
			}
			if ((subjectVarMask(i) & introducedVars) != 0L) {
				return true;
			}
		}
		return false;
	}

	private int compareGuardedBindingAssignmentOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				boolean leftGuardedBindingAssignment = isGuardedBindingAssignmentFactor(leftIndex);
				boolean rightGuardedBindingAssignment = isGuardedBindingAssignmentFactor(rightIndex);
				if (leftGuardedBindingAssignment == rightGuardedBindingAssignment) {
					return 0;
				}
				return 0;
			}
		}
		return 0;
	}

	private int compareFiniteDomainGuardOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long mask = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				int directionComparison = compareSmallBindingAssignmentGuardDirection(leftIndex, rightIndex, mask);
				if (directionComparison != 0) {
					return directionComparison;
				}
				boolean leftDomainGuard = isSmallBindingSetAssignmentGuardForFactor(leftIndex, rightIndex, mask);
				boolean rightDomainGuard = isSmallBindingSetAssignmentGuardForFactor(rightIndex, leftIndex, mask);
				if (leftDomainGuard == rightDomainGuard) {
					return 0;
				}
				PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
				PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
				if (leftDomainGuard && stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
						FINITE_DOMAIN_GUARD_MAX_STEP_WORK_RATIO)) {
					return -1;
				}
				if (rightDomainGuard && stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
						FINITE_DOMAIN_GUARD_MAX_STEP_WORK_RATIO)) {
					return 1;
				}
				return 0;
			}
			mask |= bit(leftIndex);
		}
		return 0;
	}

	private int compareSmallBindingAssignmentGuardDirection(int leftIndex, int rightIndex, long previousMask) {
		if (!isSmallBindingSetAssignment(leftIndex) || !isSmallBindingSetAssignment(rightIndex)) {
			return 0;
		}
		int leftScore = smallBindingAssignmentGuardDirectionScore(leftIndex, previousMask);
		int rightScore = smallBindingAssignmentGuardDirectionScore(rightIndex, previousMask);
		return Integer.compare(rightScore, leftScore);
	}

	private int smallBindingAssignmentGuardDirectionScore(int assignmentIndex, long previousMask) {
		long boundVars = boundVariableMask(previousMask);
		long assignmentIntroducedVars = bindingVarMasks[assignmentIndex] & ~boundVars;
		if (assignmentIntroducedVars == 0L) {
			return 0;
		}
		int score = 0;
		for (int i = 0; i < factors.size(); i++) {
			if (i == assignmentIndex || contains(previousMask, i) || isBindingSetAssignment(i)) {
				continue;
			}
			long factorIntroducedVars = bindingVarMasks[i] & ~boundVars;
			if ((factorIntroducedVars & assignmentIntroducedVars) == 0L
					|| (runtimeVarMasks[i] & boundVars) == 0L) {
				continue;
			}
			score = Math.max(score, (subjectVarMask(i) & boundVars) != 0L ? 2 : 1);
		}
		return score;
	}

	private boolean isSmallBindingSetAssignmentGuardForFactor(int assignmentIndex, int factorIndex,
			long previousMask) {
		if (!isSmallBindingSetAssignment(assignmentIndex) || isBindingSetAssignment(factorIndex)) {
			return false;
		}
		long boundVars = boundVariableMask(previousMask);
		long assignmentIntroducedVars = bindingVarMasks[assignmentIndex] & ~boundVars;
		if (assignmentIntroducedVars == 0L) {
			return false;
		}
		long factorIntroducedVars = bindingVarMasks[factorIndex] & ~boundVars;
		return (assignmentIntroducedVars & factorIntroducedVars) != 0L;
	}

	private boolean isGuardedBindingAssignmentFactor(int factorIndex) {
		TupleExpr tupleExpr = factors.get(factorIndex).tupleExpr();
		if (!(tupleExpr instanceof Filter filter)) {
			return false;
		}
		return isFilterOverBindingAssignmentWithExists(filter);
	}

	private static boolean isFilterOverBindingAssignmentWithExists(Filter filter) {
		boolean containsExists = false;
		TupleExpr current = filter;
		while (current instanceof Filter currentFilter) {
			if (containsExistsCondition(currentFilter.getCondition())) {
				containsExists = true;
			}
			current = currentFilter.getArg();
		}
		return containsExists && current instanceof BindingSetAssignment;
	}

	private static boolean containsExistsCondition(ValueExpr condition) {
		if (condition == null) {
			return false;
		}
		ExistsConditionVisitor visitor = new ExistsConditionVisitor();
		condition.visit(visitor);
		return visitor.hasExists();
	}

	private int compareBoundGuardExpansionOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long leftMask = 0L;
		long rightMask = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				boolean leftGuard = isBoundGuardFactor(leftIndex, leftMask);
				boolean rightGuard = isBoundGuardFactor(rightIndex, rightMask);
				if (leftGuard != rightGuard) {
					PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
					PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
					if (leftGuard && stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
							BOUND_GUARD_MAX_STEP_WORK_RATIO)) {
						return -1;
					}
					if (rightGuard && stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
							BOUND_GUARD_MAX_STEP_WORK_RATIO)) {
						return 1;
					}
				}
				return 0;
			}
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
		}
		return 0;
	}

	private boolean isBoundGuardFactor(int factorIndex, long previousMask) {
		if (isBindingSetAssignment(factorIndex)) {
			return false;
		}
		long factorVars = runtimeVarMasks[factorIndex];
		if (factorVars == 0L) {
			return false;
		}
		long previousBound = boundVariableMask(previousMask);
		return (factorVars & previousBound) != 0L && (factorVars & ~previousBound) == 0L;
	}

	private int compareBridgeUnlockOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long leftMask = 0L;
		long rightMask = 0L;
		long lastIntroducedVars = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				boolean leftBridge = unlocksFutureJoin(leftIndex, leftMask);
				boolean rightBridge = unlocksFutureJoin(rightIndex, rightMask);
				if (leftBridge == rightBridge) {
					return 0;
				}
				boolean leftLeaf = isLeafUnlock(leftIndex, leftMask);
				boolean rightLeaf = isLeafUnlock(rightIndex, rightMask);
				boolean leftOlderBoundLeaf = isOlderBoundRuntimeJoin(leftIndex, leftMask, lastIntroducedVars);
				boolean rightOlderBoundLeaf = isOlderBoundRuntimeJoin(rightIndex, rightMask, lastIntroducedVars);
				if (leftBridge && rightLeaf
						&& !rightOlderBoundLeaf
						&& bridgeUnlockStepComparable(left.physicalStepRanks().get(i),
								right.physicalStepRanks().get(i))) {
					return -1;
				}
				if (rightBridge && leftLeaf
						&& !leftOlderBoundLeaf
						&& bridgeUnlockStepComparable(right.physicalStepRanks().get(i),
								left.physicalStepRanks().get(i))) {
					return 1;
				}
				return 0;
			}
			long boundBeforeStep = boundVariableMask(leftMask);
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private boolean isOlderBoundLeaf(int factorIndex, long previousMask, long lastIntroducedVars) {
		return lastIntroducedVars != 0L
				&& isLeafUnlock(factorIndex, previousMask)
				&& joinStepRole(factorIndex, previousMask, lastIntroducedVars) == JoinStepRole.OLDER_BOUND_JOIN;
	}

	private boolean isOlderBoundRuntimeJoin(int factorIndex, long previousMask, long lastIntroducedVars) {
		if (lastIntroducedVars == 0L) {
			return false;
		}
		long runtimeVars = runtimeVarMasks[factorIndex];
		if (runtimeVars == 0L || (runtimeVars & lastIntroducedVars) != 0L) {
			return false;
		}
		long olderBoundVars = runtimeBoundVariableMask(previousMask) & ~lastIntroducedVars;
		return (runtimeVars & olderBoundVars) != 0L;
	}

	private int compareOlderBoundLeafOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long leftMask = 0L;
		long rightMask = 0L;
		long lastIntroducedVars = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				boolean leftOlderBoundLeaf = isOlderBoundRuntimeJoin(leftIndex, leftMask, lastIntroducedVars);
				boolean rightOlderBoundLeaf = isOlderBoundRuntimeJoin(rightIndex, rightMask, lastIntroducedVars);
				if (leftOlderBoundLeaf == rightOlderBoundLeaf) {
					return 0;
				}
				PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
				PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
				if (leftOlderBoundLeaf && stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
						BRIDGE_CONTINUATION_MAX_STEP_WORK_RATIO)) {
					return -1;
				}
				if (rightOlderBoundLeaf && stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
						BRIDGE_CONTINUATION_MAX_STEP_WORK_RATIO)) {
					return 1;
				}
				return 0;
			}
			long boundBeforeStep = boundVariableMask(leftMask);
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private boolean unlocksFutureJoin(int factorIndex, long previousMask) {
		return futureRuntimeJoinConnectionCount(factorIndex, previousMask | bit(factorIndex), previousMask) > 0;
	}

	private boolean isLeafUnlock(int factorIndex, long previousMask) {
		long nextMask = previousMask | bit(factorIndex);
		return futureRuntimeJoinConnectionCount(factorIndex, nextMask, previousMask) == 0
				&& futureDeferredFilterConnectionCount(factorIndex, nextMask, previousMask) == 0;
	}

	private int compareAnchorBridgeOrder(StatePlan left, StatePlan right) {
		return compareSpecializedJoinOrder(left, right, true);
	}

	private int compareSamePredicateLatestBridgeOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		if (size <= 1) {
			return 0;
		}
		long maskBeforeStep = 0L;
		long lastIntroducedVars = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				if (i == 0 || lastIntroducedVars == 0L || !sameConstantPredicate(leftIndex, rightIndex)) {
					return 0;
				}
				JoinStepRole leftRole = joinStepRole(leftIndex, maskBeforeStep, lastIntroducedVars);
				JoinStepRole rightRole = joinStepRole(rightIndex, maskBeforeStep, lastIntroducedVars);
				PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
				PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
				if (isLatestPathStep(leftRole) && rightRole == JoinStepRole.OLDER_BOUND_JOIN
						&& stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
								ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
					return -1;
				}
				if (isLatestPathStep(rightRole) && leftRole == JoinStepRole.OLDER_BOUND_JOIN
						&& stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
								ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
					return 1;
				}
				return 0;
			}
			long boundBeforeStep = boundVariableMask(maskBeforeStep);
			maskBeforeStep |= bit(leftIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private int compareSamePredicateAnchoredCycleOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long maskBeforeStep = 0L;
		long lastIntroducedVars = 0L;
		boolean previousStepForwardExpansion = false;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				if (!sameConstantPredicate(leftIndex, rightIndex)) {
					return 0;
				}
				PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
				PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
				if (i == 0) {
					return compareAnchoredSamePredicateSeedOrder(leftIndex, rightIndex, leftStep, rightStep);
				}
				return compareAnchoredForwardExpansionOrder(leftIndex, rightIndex, maskBeforeStep,
						lastIntroducedVars, previousStepForwardExpansion, leftStep, rightStep);
			}
			long boundBeforeStep = boundVariableMask(maskBeforeStep);
			previousStepForwardExpansion = isForwardExpansion(leftIndex, maskBeforeStep);
			maskBeforeStep |= bit(leftIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private int compareAnchoredSamePredicateSeedOrder(int leftIndex, int rightIndex, PhysicalStepRank leftStep,
			PhysicalStepRank rightStep) {
		if (initiallyBoundVarMask == 0L) {
			return 0;
		}
		boolean leftAnchored = (statementEndpointVarMask(leftIndex) & initiallyBoundVarMask) != 0L;
		boolean rightAnchored = (statementEndpointVarMask(rightIndex) & initiallyBoundVarMask) != 0L;
		if (leftAnchored != rightAnchored) {
			return leftAnchored ? -1 : 1;
		}
		if (!leftAnchored) {
			return 0;
		}
		if (stepWorkComparable(leftStep.workRows(), rightStep.workRows(), ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)
				&& leftStep.workRows() < rightStep.workRows()) {
			return -1;
		}
		if (stepWorkComparable(rightStep.workRows(), leftStep.workRows(), ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)
				&& rightStep.workRows() < leftStep.workRows()) {
			return 1;
		}
		return 0;
	}

	private int compareAnchoredForwardExpansionOrder(int leftIndex, int rightIndex, long previousMask,
			long lastIntroducedVars, boolean previousStepForwardExpansion, PhysicalStepRank leftStep,
			PhysicalStepRank rightStep) {
		boolean leftForward = anchoredForwardExpansion(leftIndex, previousMask, lastIntroducedVars,
				previousStepForwardExpansion);
		boolean rightForward = anchoredForwardExpansion(rightIndex, previousMask, lastIntroducedVars,
				previousStepForwardExpansion);
		if (leftForward == rightForward) {
			return 0;
		}
		boolean leftReverse = isReverseExpansion(leftIndex, previousMask);
		boolean rightReverse = isReverseExpansion(rightIndex, previousMask);
		if (leftForward && rightReverse
				&& stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
						ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
			return -1;
		}
		if (rightForward && leftReverse
				&& stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
						ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
			return 1;
		}
		return 0;
	}

	private boolean anchoredForwardExpansion(int factorIndex, long previousMask, long lastIntroducedVars,
			boolean previousStepForwardExpansion) {
		if (!isForwardExpansion(factorIndex, previousMask)) {
			return false;
		}
		long subjectMask = statementSubjectVarMask(factorIndex);
		return (subjectMask & initiallyBoundVarMask) != 0L
				|| (previousStepForwardExpansion && (subjectMask & lastIntroducedVars) != 0L);
	}

	private boolean isForwardExpansion(int factorIndex, long previousMask) {
		long subjectMask = statementSubjectVarMask(factorIndex);
		long objectMask = statementObjectVarMask(factorIndex);
		long boundBefore = boundVariableMask(previousMask);
		return subjectMask != 0L
				&& objectMask != 0L
				&& (subjectMask & boundBefore) != 0L
				&& (objectMask & boundBefore) == 0L;
	}

	private boolean isReverseExpansion(int factorIndex, long previousMask) {
		long subjectMask = statementSubjectVarMask(factorIndex);
		long objectMask = statementObjectVarMask(factorIndex);
		long boundBefore = boundVariableMask(previousMask);
		return subjectMask != 0L
				&& objectMask != 0L
				&& (objectMask & boundBefore) != 0L
				&& (subjectMask & boundBefore) == 0L;
	}

	private boolean isLatestPathStep(JoinStepRole role) {
		return role == JoinStepRole.ANCHOR_BRIDGE
				|| role == JoinStepRole.ANCHOR_LEAF
				|| role == JoinStepRole.CONTINUE_LATEST_BRIDGE;
	}

	private boolean sameConstantPredicate(int leftIndex, int rightIndex) {
		StatementPattern left = statementPatternFactor(leftIndex);
		StatementPattern right = statementPatternFactor(rightIndex);
		if (left == null || right == null) {
			return false;
		}
		Var leftPredicate = left.getPredicateVar();
		Var rightPredicate = right.getPredicateVar();
		return leftPredicate != null
				&& rightPredicate != null
				&& leftPredicate.hasValue()
				&& rightPredicate.hasValue()
				&& leftPredicate.getValue().equals(rightPredicate.getValue());
	}

	private StatementPattern statementPatternFactor(int factorIndex) {
		TupleExpr tupleExpr = factors.get(factorIndex).tupleExpr();
		if (tupleExpr instanceof StatementPattern statementPattern) {
			return statementPattern;
		}
		if (tupleExpr instanceof Filter filter) {
			return unwrapFilterPattern(filter);
		}
		return null;
	}

	private long statementEndpointVarMask(int factorIndex) {
		return statementSubjectVarMask(factorIndex) | statementObjectVarMask(factorIndex);
	}

	private long statementSubjectVarMask(int factorIndex) {
		StatementPattern statementPattern = statementPatternFactor(factorIndex);
		return statementPattern == null ? 0L : variableMask(statementPattern.getSubjectVar());
	}

	private long statementObjectVarMask(int factorIndex) {
		StatementPattern statementPattern = statementPatternFactor(factorIndex);
		return statementPattern == null ? 0L : variableMask(statementPattern.getObjectVar());
	}

	private long variableMask(Var var) {
		if (var == null || var.hasValue()) {
			return 0L;
		}
		Integer id = variableIds.get(var.getName());
		return id == null ? 0L : 1L << id.intValue();
	}

	private int compareBridgeContinuationOrder(StatePlan left, StatePlan right) {
		return compareSpecializedJoinOrder(left, right, false);
	}

	private int compareSpecializedJoinOrder(StatePlan left, StatePlan right, boolean anchorBridgePhase) {
		int size = Math.min(left.order().size(), right.order().size());
		if (size <= 1) {
			return 0;
		}
		long maskBeforeStep = 0L;
		long maskBeforePreviousStep = 0L;
		long lastIntroducedVars = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				if (i == 0 || lastIntroducedVars == 0L) {
					return 0;
				}
				JoinStepRole leftRole = joinStepRole(leftIndex, maskBeforeStep, lastIntroducedVars);
				JoinStepRole rightRole = joinStepRole(rightIndex, maskBeforeStep, lastIntroducedVars);
				PhysicalStepRank leftStep = left.physicalStepRanks().get(i);
				PhysicalStepRank rightStep = right.physicalStepRanks().get(i);
				if (anchorBridgePhase) {
					if (leftRole == JoinStepRole.ANCHOR_BRIDGE && rightRole == JoinStepRole.ANCHOR_LEAF
							&& stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
									ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
						return -1;
					}
					if (rightRole == JoinStepRole.ANCHOR_BRIDGE && leftRole == JoinStepRole.ANCHOR_LEAF
							&& stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
									ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
						return 1;
					}
					return 0;
				}
				if (leftRole == JoinStepRole.CONTINUE_LATEST_BRIDGE && rightRole == JoinStepRole.OLDER_BOUND_JOIN
						&& stepWorkComparable(rightStep.workRows(), leftStep.workRows(),
								BRIDGE_CONTINUATION_MAX_STEP_WORK_RATIO)) {
					return 1;
				}
				if (rightRole == JoinStepRole.CONTINUE_LATEST_BRIDGE && leftRole == JoinStepRole.OLDER_BOUND_JOIN
						&& stepWorkComparable(leftStep.workRows(), rightStep.workRows(),
								BRIDGE_CONTINUATION_MAX_STEP_WORK_RATIO)) {
					return -1;
				}
				return 0;
			}
			long boundBeforeStep = boundVariableMask(maskBeforeStep);
			maskBeforePreviousStep = maskBeforeStep;
			maskBeforeStep |= bit(leftIndex);
			lastIntroducedVars = bindingVarMasks[leftIndex] & ~boundBeforeStep;
		}
		return 0;
	}

	private JoinStepRole joinStepRole(int factorIndex, long previousMask, long lastIntroducedVars) {
		long boundBefore = boundVariableMask(previousMask);
		long introducedByFactor = bindingVarMasks[factorIndex] & ~boundBefore;
		long olderBoundVars = boundBefore & ~lastIntroducedVars;
		boolean joinsLatest = (joinVarMasks[factorIndex] & lastIntroducedVars) != 0L;
		boolean joinsOlder = (joinVarMasks[factorIndex] & olderBoundVars) != 0L;
		boolean introducesNew = introducedByFactor != 0L;
		int futureConnections = futureConnectionCount(factorIndex, previousMask | bit(factorIndex), previousMask);
		if (joinsLatest && introducesNew && !joinsOlder && futureConnections > 0) {
			return JoinStepRole.ANCHOR_BRIDGE;
		}
		if (joinsLatest && futureConnections == 0) {
			return JoinStepRole.ANCHOR_LEAF;
		}
		if (joinsLatest && introducesNew && !joinsOlder) {
			return JoinStepRole.CONTINUE_LATEST_BRIDGE;
		}
		if (joinsOlder && !joinsLatest) {
			return JoinStepRole.OLDER_BOUND_JOIN;
		}
		return JoinStepRole.OTHER;
	}

	private boolean stepWorkComparable(double preferredWorkRows, double alternativeWorkRows, double maxRatio) {
		if (!isFiniteNonNegative(preferredWorkRows) || !isFiniteNonNegative(alternativeWorkRows)
				|| !Double.isFinite(maxRatio) || maxRatio <= 0.0d) {
			return false;
		}
		return preferredWorkRows <= alternativeWorkRows * maxRatio + STRUCTURAL_WORK_EQUIVALENCE_ROWS;
	}

	private int futureRuntimeJoinConnectionCount(int factorIndex, long nextMask, long previousMask) {
		long previousBound = runtimeBoundVariableMask(previousMask);
		long introducedVars = runtimeVarMasks[factorIndex] & ~previousBound;
		if (introducedVars == 0L) {
			return 0;
		}

		long nextBound = runtimeBoundVariableMask(nextMask);
		int futureConnections = 0;
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(nextMask, i)
					&& (runtimeVarMasks[i] & introducedVars) != 0L
					&& (runtimeVarMasks[i] & ~nextBound) != 0L) {
				futureConnections++;
			}
		}
		return futureConnections;
	}

	private long runtimeBoundVariableMask(long mask) {
		long bound = initiallyBoundVarMask;
		for (int i = 0; i < factors.size(); i++) {
			if (contains(mask, i)) {
				bound |= runtimeVarMasks[i];
			}
		}
		return bound;
	}

	private boolean bridgeUnlockStepComparable(PhysicalStepRank bridgeStep, PhysicalStepRank leafStep) {
		if (!isFiniteNonNegative(bridgeStep.workRows()) || !isFiniteNonNegative(leafStep.workRows())) {
			return false;
		}
		return bridgeStep.workRows() <= leafStep.workRows() * BRIDGE_UNLOCK_MAX_STEP_WORK_RATIO
				+ STRUCTURAL_WORK_EQUIVALENCE_ROWS;
	}

	private List<String> newlyUnlockedFilterLabels(long previousMask, long nextMask) {
		return newlyUnlockedFilterLabels(previousMask, nextMask, null);
	}

	private List<String> newlyUnlockedFilterLabels(long previousMask, long nextMask,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		if (deferredFilters.isEmpty()) {
			return List.of();
		}
		long previousBound = boundVariableMask(previousMask);
		long nextBound = boundVariableMask(nextMask);
		List<String> labels = new ArrayList<>();
		for (int i = 0; i < deferredFilters.size(); i++) {
			JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(i);
			if (isDeferredFilterNewlyPlaced(i, previousMask, nextMask, previousBound, nextBound)) {
				labels.add(describeUnlockedFilter(filter, rowsEnteringEstimate));
			}
		}
		return labels;
	}

	private String describeAlternative(long previousMask, StatePlan prefix, int candidate, StatePlan candidatePlan,
			double prefixWorkRows, boolean accepted) {
		double prefixRows = prefix == null ? 0.0d : prefix.estimate().outputRows();
		double nestedFilterWorkRows = alternativeNestedFilterWorkRows(previousMask, prefix, candidate,
				candidatePlan.mask());
		PhysicalStepRank physicalStepRank = candidatePlan.physicalStepRanks()
				.get(candidatePlan.physicalStepRanks().size() - 1);
		List<String> unlockedFilters = newlyUnlockedFilterLabels(previousMask, candidatePlan.mask());
		return "order=" + describeFactorOrder(candidatePlan.order())
				+ ", candidate=" + describeFactor(candidate)
				+ ", prefixRows=" + prefixRows
				+ ", factorWorkRows=" + physicalStepRank.workRows()
				+ ", nestedFilterWorkRows=" + nestedFilterWorkRows
				+ ", stepWorkRows=" + (candidatePlan.totalWork() - prefixWorkRows)
				+ ", totalWork=" + candidatePlan.totalWork()
				+ ", filterPlacement=" + (unlockedFilters.isEmpty() ? "none" : unlockedFilters)
				+ ", accepted=" + accepted
				+ ", rejectionReason=" + (accepted ? "none" : "frontier-pruned");
	}

	private double alternativeNestedFilterWorkRows(long previousMask, StatePlan prefix, int candidate, long nextMask) {
		double rowsEnteringFilter;
		SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate;
		if (prefix == null) {
			rowsEnteringEstimate = factors.get(candidate).estimate();
			rowsEnteringFilter = rowsEnteringEstimate.outputRows();
		} else {
			SketchBasedJoinEstimator.JoinStepEstimate step = estimateTransition(previousMask, prefix.estimate(),
					candidate);
			rowsEnteringFilter = step.outputRows();
			rowsEnteringEstimate = estimator.joinedPlanEstimate(step);
		}
		return newlyUnlockedFilterWorkRows(previousMask, nextMask, rowsEnteringFilter, rowsEnteringEstimate);
	}

	private String describeUnlockedFilter(JoinOrderPlanner.FilterConstraint filter,
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate) {
		String label = singleLineMetricValue(filter.getDebugLabel());
		double passRatio = filter.getEstimatedPassRatio();
		String selectivitySource = filter.getSelectivitySource();
		double nestedExistsPassRatio = nestedExistsPassRatio(filter, rowsEnteringEstimate);
		if (isValidPassRatio(nestedExistsPassRatio)) {
			passRatio = nestedExistsPassRatio;
			selectivitySource = "sketch_nested_exists";
		}
		if (Double.isFinite(passRatio) && passRatio >= 0.0d && passRatio <= 1.0d) {
			label += " passRatio=" + passRatio;
		}
		if (selectivitySource != null) {
			label += " source=" + selectivitySource;
		}
		if (filter.getEvidenceCount() >= 0L) {
			label += " evidence=" + filter.getEvidenceCount();
		}
		return label;
	}

	private String singleLineMetricValue(String value) {
		if (value == null || value.isEmpty()) {
			return "";
		}
		StringBuilder builder = new StringBuilder(value.length());
		boolean previousWhitespace = false;
		for (int i = 0; i < value.length(); i++) {
			char c = value.charAt(i);
			if (Character.isWhitespace(c)) {
				if (!previousWhitespace && builder.length() > 0) {
					builder.append(' ');
				}
				previousWhitespace = true;
			} else {
				builder.append(c);
				previousWhitespace = false;
			}
		}
		int length = builder.length();
		if (length > 0 && builder.charAt(length - 1) == ' ') {
			builder.setLength(length - 1);
		}
		return builder.toString();
	}

	private List<JoinOrderPlanner.PlanStep> buildPlanSteps(List<Integer> order) {
		List<JoinOrderPlanner.PlanStep> steps = new ArrayList<>(order.size());
		long mask = 0L;
		SketchBasedJoinEstimator.TuplePlanEstimate prefixEstimate = null;
		for (Integer next : order) {
			int factorIndex = next.intValue();
			Set<String> boundBefore = boundVariables(mask);
			long boundBeforeMask = boundVariableMask(mask);
			long nextMask = mask | bit(factorIndex);
			double factorOutputRows;
			double stepWorkRows;
			SketchBasedJoinEstimator.TuplePlanEstimate rowsEnteringEstimate;
			SketchBasedJoinEstimator.TuplePlanEstimate nextEstimate;
			SketchBasedJoinEstimator.TuplePlanEstimate conditionedEstimate = conditionedFactorEstimate(factorIndex,
					boundBeforeMask);
			FactorPhysicalEstimate physicalEstimate = factorPhysicalEstimate(factorIndex, mask, boundBeforeMask,
					conditionedEstimate.outputRows(), prefixEstimate);
			factorOutputRows = physicalEstimate.factorOutputRows();
			if (mask == 0L) {
				SketchBasedJoinEstimator.TuplePlanEstimate factorEstimate = factors.get(factorIndex).estimate();
				stepWorkRows = stepWorkRows(mask, nextMask, physicalEstimate.workRows(), factorEstimate.outputRows(),
						factorEstimate);
				rowsEnteringEstimate = factorEstimate;
				nextEstimate = applyUnlockedFilters(mask, nextMask, rowsEnteringEstimate);
			} else {
				SketchBasedJoinEstimator.JoinStepEstimate step = estimateTransition(mask, prefixEstimate, factorIndex);
				rowsEnteringEstimate = rowsEnteringEstimate(mask,
						factorIndex, prefixEstimate, step);
				stepWorkRows = stepWorkRows(mask, nextMask, physicalEstimate.workRows(),
						rowsEnteringEstimate.outputRows(),
						rowsEnteringEstimate);
				nextEstimate = applyUnlockedFilters(mask, nextMask, rowsEnteringEstimate);
			}

			Map<String, String> stringMetrics = new HashMap<>();
			Map<String, Double> doubleMetrics = new HashMap<>();
			addPhysicalMetrics(stringMetrics, doubleMetrics, physicalEstimate);
			Set<String> sharedJoinVars = sharedJoinVars(factors.get(factorIndex).tupleExpr(), boundBefore);
			if (!sharedJoinVars.isEmpty()) {
				stringMetrics.put(TelemetryMetricNames.SHARED_JOIN_VARS, sharedJoinVars.toString());
			}
			List<String> unlockedFilterLabels = newlyUnlockedFilterLabels(mask, nextMask, rowsEnteringEstimate);
			if (!unlockedFilterLabels.isEmpty()) {
				stringMetrics.put(TelemetryMetricNames.UNLOCKED_FILTERS, String.join(", ", unlockedFilterLabels));
			}
			steps.add(new JoinOrderPlanner.PlanStep(boundBefore, factorOutputRows, nextEstimate.outputRows(),
					stepWorkRows, stringMetrics, doubleMetrics));
			mask = nextMask;
			prefixEstimate = nextEstimate;
		}
		return List.copyOf(steps);
	}

	private void addPhysicalMetrics(Map<String, String> stringMetrics, Map<String, Double> doubleMetrics,
			FactorPhysicalEstimate physicalEstimate) {
		JoinFactorCostModel.FactorCostEstimate factorCostEstimate = physicalEstimate.factorCostEstimate();
		if (factorCostEstimate == null) {
			return;
		}
		stringMetrics.putAll(factorCostEstimate.getStringMetrics());
		doubleMetrics.putAll(factorCostEstimate.getDoubleMetrics());
	}

	private Set<String> sharedJoinVars(TupleExpr tupleExpr, Set<String> boundBefore) {
		TreeSet<String> shared = new TreeSet<>();
		for (String bindingName : tupleExpr.getBindingNames()) {
			if (!bindingName.startsWith("_const_") && boundBefore.contains(bindingName)) {
				shared.add(bindingName);
			}
		}
		return shared;
	}

	private List<Integer> indices() {
		List<Integer> indices = new ArrayList<>(factors.size());
		for (int i = 0; i < factors.size(); i++) {
			indices.add(i);
		}
		return List.copyOf(indices);
	}

	private void logFactorEstimates() {
		for (int i = 0; i < factors.size(); i++) {
			PlanFactor factor = factors.get(i);
			recordDebug("factor[" + i + "]: expr=" + describeTupleExpr(factor.tupleExpr()) + " estimate="
					+ factor.estimate().summary());
		}
	}

	private void recordDebug(String message) {
		diagnostics.add(message);
		logger.debug("Sketch join reorder {}", message);
	}

	private void recordLogicalCandidate(StateFrontier frontier, boolean accepted) {
		logicalCandidateCount++;
		if (accepted) {
			logicalAcceptedCount++;
		} else {
			logicalRejectedAlternatives++;
		}
		logicalMaxFrontierWidth = Math.max(logicalMaxFrontierWidth, frontier.size());
	}

	private String logicalExplorationSummary() {
		return "mode=" + (logicalExplorationMode == null ? "unknown" : logicalExplorationMode)
				+ ", frontierLimit=" + FRONTIER_LIMIT
				+ ", beamWidth=" + GREEDY_BEAM_WIDTH
				+ ", candidates=" + logicalCandidateCount
				+ ", accepted=" + logicalAcceptedCount
				+ ", rejectedAlternatives=" + logicalRejectedAlternatives
				+ ", maxFrontierWidth=" + logicalMaxFrontierWidth
				+ ", finalFrontierWidth=" + logicalFinalFrontierWidth;
	}

	private String runtimeCorrectionHints() {
		if (deferredFilters.isEmpty()) {
			return "runtimeCorrection=none";
		}
		return "runtimeCorrection=filter-feedback-candidate, deferredFilters=" + deferredFilters.size();
	}

	private String runtimeFeedbackSummary() {
		if (deferredFilters.isEmpty()) {
			return "filterFeedback=none";
		}

		Map<String, Integer> sources = new TreeMap<>();
		int knownPassRatios = 0;
		long totalEvidence = 0L;
		for (JoinOrderPlanner.FilterConstraint filter : deferredFilters) {
			String source = filter.getSelectivitySource();
			if (source == null || source.isEmpty()) {
				source = "unknown";
			}
			sources.merge(source, 1, Integer::sum);
			double passRatio = filter.getEstimatedPassRatio();
			if (Double.isFinite(passRatio) && passRatio >= 0.0d && passRatio <= 1.0d) {
				knownPassRatios++;
			}
			long evidenceCount = filter.getEvidenceCount();
			if (evidenceCount > 0L) {
				totalEvidence += evidenceCount;
			}
		}
		return "filterFeedback=deferredFilters=" + deferredFilters.size()
				+ ", knownPassRatios=" + knownPassRatios
				+ ", sources=" + sources
				+ ", totalEvidence=" + totalEvidence;
	}

	private double runtimeFeedbackConfidence() {
		if (deferredFilters.isEmpty()) {
			return Double.NaN;
		}
		double confidence = 1.0d;
		for (JoinOrderPlanner.FilterConstraint filter : deferredFilters) {
			confidence = Math.min(confidence, filterFeedbackConfidence(filter));
		}
		return confidence;
	}

	private double filterFeedbackConfidence(JoinOrderPlanner.FilterConstraint filter) {
		long evidenceCount = filter.getEvidenceCount();
		if (evidenceCount >= 0L) {
			return evidenceCount / (evidenceCount + 64.0d);
		}
		String source = filter.getSelectivitySource();
		if ("heuristic".equals(source)) {
			return 0.25d;
		}
		if ("learned_filter".equals(source) || "learned_template".equals(source)
				|| "learned_pattern".equals(source) || "sampled".equals(source)) {
			return 0.5d;
		}
		return 0.0d;
	}

	private String summarizeDiagnostics(List<String> diagnostics) {
		if (diagnostics.size() == 1) {
			return diagnostics.get(0);
		}
		if (traceDiagnostics) {
			return String.join("; ", diagnostics);
		}
		return diagnostics.get(0) + "; " + diagnostics.get(diagnostics.size() - 1);
	}

	private String describeFactor(int index) {
		PlanFactor factor = factors.get(index);
		return factor.index() + ":" + describeTupleExpr(factor.tupleExpr());
	}

	private String describeFactorOrder(List<Integer> order) {
		List<String> labels = new ArrayList<>(order.size());
		for (Integer index : order) {
			labels.add(describeFactor(index.intValue()));
		}
		return labels.toString();
	}

	private long allMask() {
		return (1L << factors.size()) - 1L;
	}

	private static long maskOf(List<Integer> order) {
		long mask = 0L;
		for (Integer index : order) {
			mask |= bit(index.intValue());
		}
		return mask;
	}

	private static boolean contains(long mask, int index) {
		return (mask & bit(index)) != 0L;
	}

	private static boolean isFiniteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d;
	}

	private static boolean isValidPassRatio(double value) {
		return Double.isFinite(value) && value >= 0.0d && value <= 1.0d;
	}

	private static long bit(int index) {
		return 1L << index;
	}

	private boolean isBetter(StatePlan candidate, StatePlan incumbent) {
		if (candidate == null) {
			return false;
		}
		if (incumbent == null) {
			return true;
		}
		if (candidate.mask() == incumbent.mask()) {
			int correlatedSeedComparison = compareCorrelatedSeedOrder(candidate.order(), incumbent.order());
			if (correlatedSeedComparison != 0) {
				return correlatedSeedComparison < 0;
			}
			int cheaperNonTypeSeedComparison = compareCheaperNonTypeSeedOrder(candidate, incumbent);
			if (cheaperNonTypeSeedComparison != 0) {
				return cheaperNonTypeSeedComparison < 0;
			}
			int finiteDomainGuardComparison = compareFiniteDomainGuardOrder(candidate, incumbent);
			if (finiteDomainGuardComparison != 0) {
				return finiteDomainGuardComparison < 0;
			}
			int subjectTypeBoundGuardComparison = compareSubjectTypeBoundGuardExpansionOrder(candidate, incumbent);
			if (subjectTypeBoundGuardComparison != 0) {
				return subjectTypeBoundGuardComparison < 0;
			}
		}
		boolean structurallyComparableWork = structurallyComparableWork(candidate.totalWork(), incumbent.totalWork());
		if (structurallyComparableWork && candidate.mask() == incumbent.mask()) {
			int deferredFilterComparison = compareDeferredFilterOrder(candidate.order(), incumbent.order());
			if (deferredFilterComparison != 0) {
				return deferredFilterComparison < 0;
			}
			int guardedBindingComparison = compareGuardedBindingAssignmentOrder(candidate, incumbent);
			if (guardedBindingComparison != 0) {
				return guardedBindingComparison < 0;
			}
			int boundGuardComparison = compareBoundGuardOrder(candidate.order(), incumbent.order());
			if (boundGuardComparison != 0) {
				return boundGuardComparison < 0;
			}
			int finiteDomainGuardComparison = compareFiniteDomainGuardOrder(candidate, incumbent);
			if (finiteDomainGuardComparison != 0) {
				return finiteDomainGuardComparison < 0;
			}
			int narrowAnchorComparison = compareNarrowAnchorOrder(candidate, incumbent);
			if (narrowAnchorComparison != 0) {
				return narrowAnchorComparison < 0;
			}
		}
		if (structurallyComparableWork && candidate.mask() == incumbent.mask()) {
			int bridgeUnlockComparison = compareBridgeUnlockOrder(candidate, incumbent);
			if (bridgeUnlockComparison != 0) {
				return bridgeUnlockComparison < 0;
			}
		}
		int connectivityComparison = compareOrderConnectivity(candidate.order(), incumbent.order());
		if (connectivityComparison != 0 && structurallyComparableWork) {
			return connectivityComparison < 0;
		}
		if (structurallyComparableWork && candidate.mask() == incumbent.mask()) {
			int physicalOrderComparison = comparePhysicalStepOrder(candidate, incumbent);
			if (physicalOrderComparison != 0) {
				return physicalOrderComparison < 0;
			}
		}
		if (candidate.mask() == incumbent.mask()) {
			int anchoredCycleComparison = compareSamePredicateAnchoredCycleOrder(candidate, incumbent);
			if (anchoredCycleComparison != 0) {
				return anchoredCycleComparison < 0;
			}
			int latestBridgeComparison = compareSamePredicateLatestBridgeOrder(candidate, incumbent);
			if (latestBridgeComparison != 0) {
				return latestBridgeComparison < 0;
			}
		}
		int workComparison = Double.compare(candidate.totalWork(), incumbent.totalWork());
		if (workComparison != 0) {
			return workComparison < 0;
		}
		int rowsComparison = Double.compare(candidate.estimate().outputRows(), incumbent.estimate().outputRows());
		if (rowsComparison != 0) {
			return rowsComparison < 0;
		}
		int physicalOrderComparison = comparePhysicalStepOrder(candidate, incumbent);
		if (physicalOrderComparison != 0) {
			return physicalOrderComparison < 0;
		}
		if (structurallyComparableWork && candidate.mask() == incumbent.mask()) {
			int olderBoundLeafComparison = compareOlderBoundLeafOrder(candidate, incumbent);
			if (olderBoundLeafComparison != 0) {
				return olderBoundLeafComparison < 0;
			}
			int guardExpansionComparison = compareBoundGuardExpansionOrder(candidate, incumbent);
			if (guardExpansionComparison != 0) {
				return guardExpansionComparison < 0;
			}
			int anchorBridgeComparison = compareAnchorBridgeOrder(candidate, incumbent);
			if (anchorBridgeComparison != 0) {
				return anchorBridgeComparison < 0;
			}
			int continuationComparison = compareBridgeContinuationOrder(candidate, incumbent);
			if (continuationComparison != 0) {
				return continuationComparison < 0;
			}
		}
		if (connectivityComparison != 0) {
			return connectivityComparison < 0;
		}
		return compareOrder(candidate.order(), incumbent.order()) < 0;
	}

	private int compareCorrelatedSeedOrder(List<Integer> left, List<Integer> right) {
		if (initiallyBoundVarMask == 0L || left.isEmpty() || right.isEmpty()
				|| !hasFactorConnectedToInitiallyBoundVars()) {
			return 0;
		}
		boolean leftStartsCorrelated = (runtimeVarMasks[left.get(0).intValue()] & initiallyBoundVarMask) != 0L;
		boolean rightStartsCorrelated = (runtimeVarMasks[right.get(0).intValue()] & initiallyBoundVarMask) != 0L;
		if (leftStartsCorrelated == rightStartsCorrelated) {
			return 0;
		}
		return leftStartsCorrelated ? -1 : 1;
	}

	private int compareCheaperNonTypeSeedOrder(StatePlan left, StatePlan right) {
		if (left.order().isEmpty() || right.order().isEmpty()) {
			return 0;
		}
		int leftSeed = left.order().get(0).intValue();
		int rightSeed = right.order().get(0).intValue();
		if (leftSeed == rightSeed || isSubjectTypeGuard(leftSeed) == isSubjectTypeGuard(rightSeed)) {
			return 0;
		}
		double leftSeedWorkRows = left.physicalStepRanks().get(0).workRows();
		double rightSeedWorkRows = right.physicalStepRanks().get(0).workRows();
		if (!isFiniteNonNegative(leftSeedWorkRows) || !isFiniteNonNegative(rightSeedWorkRows)) {
			return 0;
		}
		int filteredSeedComparison = compareFilteredSeedAgainstSubjectTypeGuardOrder(leftSeed, rightSeed,
				leftSeedWorkRows, rightSeedWorkRows);
		if (filteredSeedComparison != 0) {
			return filteredSeedComparison;
		}
		int subjectTypeGuardComparison = compareSubjectTypeSeedGuardOrder(leftSeed, rightSeed, leftSeedWorkRows,
				rightSeedWorkRows);
		if (subjectTypeGuardComparison != 0) {
			return subjectTypeGuardComparison;
		}
		if (!isSubjectTypeGuard(leftSeed) && leftSeedWorkRows < rightSeedWorkRows) {
			return -1;
		}
		if (!isSubjectTypeGuard(rightSeed) && rightSeedWorkRows < leftSeedWorkRows) {
			return 1;
		}
		return 0;
	}

	private int compareFilteredSeedAgainstSubjectTypeGuardOrder(int leftSeed, int rightSeed, double leftSeedWorkRows,
			double rightSeedWorkRows) {
		if (isFilteredSeedFactor(leftSeed)
				&& filteredFactorSharesSubjectTypeGuard(leftSeed, rightSeed)
				&& stepWorkComparable(leftSeedWorkRows, rightSeedWorkRows, FILTERED_SEED_MAX_STEP_WORK_RATIO)) {
			return -1;
		}
		if (isFilteredSeedFactor(rightSeed)
				&& filteredFactorSharesSubjectTypeGuard(rightSeed, leftSeed)
				&& stepWorkComparable(rightSeedWorkRows, leftSeedWorkRows, FILTERED_SEED_MAX_STEP_WORK_RATIO)) {
			return 1;
		}
		return 0;
	}

	private boolean filteredFactorSharesSubjectTypeGuard(int filteredIndex, int guardIndex) {
		return isFilteredSeedFactor(filteredIndex)
				&& isSubjectTypeGuard(guardIndex)
				&& (subjectVarMask(guardIndex) & runtimeVarMasks[filteredIndex]) != 0L;
	}

	private int compareSubjectTypeSeedGuardOrder(int leftSeed, int rightSeed, double leftSeedWorkRows,
			double rightSeedWorkRows) {
		boolean leftSubjectTypeGuard = isSubjectTypeGuard(leftSeed);
		boolean rightSubjectTypeGuard = isSubjectTypeGuard(rightSeed);
		if (leftSubjectTypeGuard == rightSubjectTypeGuard) {
			return 0;
		}
		if (leftSubjectTypeGuard
				&& subjectTypeGuardConstrainsFactor(leftSeed, rightSeed)
				&& stepWorkComparable(leftSeedWorkRows, rightSeedWorkRows, BOUND_GUARD_MAX_STEP_WORK_RATIO)) {
			return -1;
		}
		if (rightSubjectTypeGuard
				&& subjectTypeGuardConstrainsFactor(rightSeed, leftSeed)
				&& stepWorkComparable(rightSeedWorkRows, leftSeedWorkRows, BOUND_GUARD_MAX_STEP_WORK_RATIO)) {
			return 1;
		}
		return 0;
	}

	private boolean subjectTypeGuardConstrainsFactor(int guardIndex, int factorIndex) {
		return isSubjectTypeGuard(guardIndex)
				&& !isFilteredSeedFactor(factorIndex)
				&& (subjectVarMask(guardIndex) & runtimeVarMasks[factorIndex]) != 0L;
	}

	private boolean isFilteredSeedFactor(int factorIndex) {
		return isFilteredFactor(factorIndex) || unlocksSelectivePositiveNestedFilter(factorIndex, 0L);
	}

	private boolean isFilteredFactor(int factorIndex) {
		return factors.get(factorIndex).tupleExpr() instanceof Filter;
	}

	private boolean unlocksSelectivePositiveNestedFilter(int factorIndex, long previousMask) {
		if (deferredFilters.isEmpty()) {
			return false;
		}
		long previousBound = boundVariableMask(previousMask);
		long nextBound = boundVariableMask(previousMask | bit(factorIndex));
		for (int i = 0; i < deferredFilters.size(); i++) {
			JoinOrderPlanner.FilterConstraint filter = deferredFilters.get(i);
			if (!filter.hasNestedTupleExpression() || filter.isNotExists()) {
				continue;
			}
			if (!hasSelectiveOrderingPassRatio(filter)) {
				continue;
			}
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if (requiredVars != 0L
					&& (previousBound & requiredVars) != requiredVars
					&& (nextBound & requiredVars) == requiredVars) {
				return true;
			}
		}
		return false;
	}

	private static boolean hasSelectiveOrderingPassRatio(JoinOrderPlanner.FilterConstraint filter) {
		double passRatio = filter.getEstimatedPassRatio();
		return Double.isFinite(passRatio) && passRatio >= 0.0d
				&& passRatio <= DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO;
	}

	private int compareNarrowAnchorOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.order().size(), right.order().size());
		long leftMask = 0L;
		long rightMask = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.order().get(i).intValue();
			int rightIndex = right.order().get(i).intValue();
			if (leftIndex != rightIndex) {
				if ((runtimeVarMasks[leftIndex] & runtimeVarMasks[rightIndex]) == 0L) {
					return 0;
				}
				long leftIntroduced = bindingVarMasks[leftIndex] & ~boundVariableMask(leftMask);
				long rightIntroduced = bindingVarMasks[rightIndex] & ~boundVariableMask(rightMask);
				if (isStrictSubset(leftIntroduced, rightIntroduced)
						&& stepWorkComparable(left.physicalStepRanks().get(i).workRows(),
								right.physicalStepRanks().get(i).workRows(), ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
					return -1;
				}
				if (isStrictSubset(rightIntroduced, leftIntroduced)
						&& stepWorkComparable(right.physicalStepRanks().get(i).workRows(),
								left.physicalStepRanks().get(i).workRows(), ANCHOR_BRIDGE_MAX_STEP_WORK_RATIO)) {
					return 1;
				}
				return 0;
			}
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
		}
		return 0;
	}

	private static boolean isStrictSubset(long subset, long superset) {
		return subset != 0L && subset != superset && (subset & superset) == subset;
	}

	private boolean structurallyComparableWork(double leftWorkRows, double rightWorkRows) {
		if (!isFiniteNonNegative(leftWorkRows) || !isFiniteNonNegative(rightWorkRows)) {
			return false;
		}
		return Math.abs(leftWorkRows - rightWorkRows) <= STRUCTURAL_WORK_EQUIVALENCE_ROWS;
	}

	private int compareDeferredFilterOrder(List<Integer> left, List<Integer> right) {
		if (deferredFilters.isEmpty()) {
			return 0;
		}
		DeferredFilterOrderRank leftRank = deferredFilterOrderRank(left);
		DeferredFilterOrderRank rightRank = deferredFilterOrderRank(right);
		if (leftRank.filterCount() == 0 || rightRank.filterCount() == 0) {
			return 0;
		}
		int unlockComparison = compareFiniteAscending(leftRank.unlockScore(), rightRank.unlockScore());
		if (unlockComparison != 0) {
			return unlockComparison;
		}
		return compareFiniteAscending(leftRank.windowScore(), rightRank.windowScore());
	}

	private DeferredFilterOrderRank deferredFilterOrderRank(List<Integer> order) {
		long orderBoundVars = initiallyBoundVarMask;
		for (Integer factorIndex : order) {
			orderBoundVars |= bindingVarMasks[factorIndex.intValue()];
		}

		int filterCount = 0;
		double unlockScore = 0.0d;
		double windowScore = 0.0d;
		for (int i = 0; i < deferredFilters.size(); i++) {
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if (requiredVars == 0L
					|| (initiallyBoundVarMask & requiredVars) == requiredVars
					|| (orderBoundVars & requiredVars) != requiredVars) {
				continue;
			}
			DeferredFilterPlacement placement = deferredFilterPlacement(order, requiredVars);
			double weight = deferredFilterOrderingWeight(deferredFilters.get(i));
			if (weight <= 0.0d) {
				continue;
			}
			filterCount++;
			unlockScore += weight * placement.unlockStep();
			windowScore += weight * placement.windowWidth();
		}
		return new DeferredFilterOrderRank(filterCount, unlockScore, windowScore);
	}

	private DeferredFilterPlacement deferredFilterPlacement(List<Integer> order, long requiredVars) {
		long bound = initiallyBoundVarMask;
		int firstStep = -1;
		for (int step = 0; step < order.size(); step++) {
			long introducedVars = bindingVarMasks[order.get(step).intValue()] & ~bound;
			if (firstStep < 0 && (introducedVars & requiredVars) != 0L) {
				firstStep = step;
			}
			bound |= bindingVarMasks[order.get(step).intValue()];
			if ((bound & requiredVars) == requiredVars) {
				return new DeferredFilterPlacement(step, firstStep < 0 ? 1 : step - firstStep + 1);
			}
		}
		return new DeferredFilterPlacement(order.size(), order.size() + 1);
	}

	private double deferredFilterOrderingWeight(JoinOrderPlanner.FilterConstraint filter) {
		if (!canApplyPassRatioToOutputRows(filter) || filter.isLookupCompatible()) {
			return 0.0d;
		}
		double passRatio = filter.getEstimatedPassRatio();
		if (Double.isFinite(passRatio) && passRatio >= 0.0d
				&& passRatio <= DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO) {
			return 1.0d + (DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO - passRatio);
		}
		return 0.0d;
	}

	private int comparePhysicalStepOrder(StatePlan left, StatePlan right) {
		if (factorCostModel == null) {
			return 0;
		}
		int size = Math.min(left.order().size(), right.order().size());
		for (int i = 0; i < size; i++) {
			if (left.order().get(i).equals(right.order().get(i))) {
				continue;
			}
			int comparison = comparePhysicalStep(left.physicalStepRanks().get(i), right.physicalStepRanks().get(i));
			if (comparison != 0) {
				return comparison;
			}
		}
		return 0;
	}

	private int comparePhysicalStep(PhysicalStepRank left, PhysicalStepRank right) {
		if (!left.comparable() || !right.comparable()) {
			return 0;
		}
		int missingComparison = Integer.compare(left.missingLookupComponents(), right.missingLookupComponents());
		if (missingComparison != 0) {
			return missingComparison;
		}
		int directLookupComparison = Boolean.compare(right.directLookup(), left.directLookup());
		if (directLookupComparison != 0) {
			return directLookupComparison;
		}
		int rowsComparison = compareFiniteAscending(left.factorOutputRows(), right.factorOutputRows());
		if (rowsComparison != 0) {
			return rowsComparison;
		}
		int workComparison = compareFiniteAscending(left.workRows(), right.workRows());
		if (workComparison != 0) {
			return workComparison;
		}
		int subjectPrefixComparison = compareSubjectPrefixPreference(left, right);
		if (subjectPrefixComparison != 0) {
			return subjectPrefixComparison;
		}
		int lookupComparison = Integer.compare(right.lookupComponents(), left.lookupComponents());
		if (lookupComparison != 0) {
			return lookupComparison;
		}
		return compareFiniteAscending(left.accessRowsBeforeFilter(), right.accessRowsBeforeFilter());
	}

	private int compareSubjectPrefixPreference(PhysicalStepRank left, PhysicalStepRank right) {
		boolean leftSubjectPrefix = hasLookupComponent(left, SketchBasedJoinEstimator.Component.S)
				&& !hasLookupComponent(left, SketchBasedJoinEstimator.Component.O);
		boolean rightSubjectPrefix = hasLookupComponent(right, SketchBasedJoinEstimator.Component.S)
				&& !hasLookupComponent(right, SketchBasedJoinEstimator.Component.O);
		if (leftSubjectPrefix == rightSubjectPrefix) {
			return 0;
		}
		return leftSubjectPrefix ? -1 : 1;
	}

	private boolean hasLookupComponent(PhysicalStepRank rank, SketchBasedJoinEstimator.Component component) {
		return (rank.lookupComponentMask() & (1 << component.ordinal())) != 0;
	}

	private static int compareFiniteAscending(double left, double right) {
		boolean leftFinite = isFiniteNonNegative(left);
		boolean rightFinite = isFiniteNonNegative(right);
		if (leftFinite && rightFinite) {
			return Double.compare(left, right);
		}
		if (leftFinite != rightFinite) {
			return leftFinite ? -1 : 1;
		}
		return 0;
	}

	private int componentCount(String componentMask) {
		if (componentMask == null || "[]".equals(componentMask)) {
			return 0;
		}
		int count = 1;
		for (int i = 0; i < componentMask.length(); i++) {
			if (componentMask.charAt(i) == ',') {
				count++;
			}
		}
		return count;
	}

	private int componentMask(String componentMask) {
		if (componentMask == null || "[]".equals(componentMask)) {
			return 0;
		}
		int mask = 0;
		for (SketchBasedJoinEstimator.Component component : SketchBasedJoinEstimator.Component.values()) {
			if (componentMask.contains(component.name())) {
				mask |= 1 << component.ordinal();
			}
		}
		return mask;
	}

	private int compareOrderConnectivity(List<Integer> left, List<Integer> right) {
		int size = Math.min(left.size(), right.size());
		long leftMask = 0L;
		long rightMask = 0L;
		for (int i = 0; i < size; i++) {
			int leftIndex = left.get(i);
			int rightIndex = right.get(i);
			if (leftIndex != rightIndex) {
				int leftConnections = futureConnectionCount(leftIndex, leftMask | bit(leftIndex), leftMask);
				int rightConnections = futureConnectionCount(rightIndex, rightMask | bit(rightIndex), rightMask);
				int comparison = Integer.compare(rightConnections, leftConnections);
				if (comparison != 0) {
					return comparison;
				}
			}
			leftMask |= bit(leftIndex);
			rightMask |= bit(rightIndex);
		}
		return 0;
	}

	private int futureConnectionCount(int factorIndex, long nextMask, long previousMask) {
		return futureJoinConnectionCount(factorIndex, nextMask, previousMask)
				+ futureDeferredFilterConnectionCount(factorIndex, nextMask, previousMask);
	}

	private int futureJoinConnectionCount(int factorIndex, long nextMask, long previousMask) {
		long previousBound = boundVariableMask(previousMask);
		long introducedVars = joinVarMasks[factorIndex] & ~previousBound;
		if (introducedVars == 0L) {
			return 0;
		}

		long nextBound = boundVariableMask(nextMask);
		int futureConnections = 0;
		for (int i = 0; i < factors.size(); i++) {
			if (!contains(nextMask, i)
					&& (joinVarMasks[i] & introducedVars) != 0L
					&& (bindingVarMasks[i] & ~nextBound) != 0L) {
				futureConnections++;
			}
		}
		return futureConnections;
	}

	private int futureDeferredFilterConnectionCount(int factorIndex, long nextMask, long previousMask) {
		if (deferredFilters.isEmpty()) {
			return 0;
		}
		long previousBound = boundVariableMask(previousMask);
		long introducedVars = bindingVarMasks[factorIndex] & ~previousBound;
		if (introducedVars == 0L) {
			return 0;
		}

		long nextBound = boundVariableMask(nextMask);
		int futureConnections = 0;
		for (int i = 0; i < deferredFilters.size(); i++) {
			if (deferredFilterOrderingWeight(deferredFilters.get(i)) <= 0.0d) {
				continue;
			}
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if ((previousBound & requiredVars) == requiredVars
					|| (requiredVars & introducedVars) == 0L) {
				continue;
			}
			if ((nextBound & requiredVars) == requiredVars) {
				futureConnections += completedDeferredFilterConnectionWeight(deferredFilters.get(i));
				continue;
			}
			long missingVars = requiredVars & ~nextBound;
			for (int j = 0; j < factors.size(); j++) {
				if (!contains(nextMask, j) && (bindingVarMasks[j] & missingVars) != 0L) {
					futureConnections++;
				}
			}
		}
		return futureConnections;
	}

	private int completedDeferredFilterConnectionWeight(JoinOrderPlanner.FilterConstraint filter) {
		return deferredFilterOrderingWeight(filter) > 0.0d ? COMPLETED_DEFERRED_FILTER_CONNECTIONS : 0;
	}

	private static int compareOrder(List<Integer> left, List<Integer> right) {
		int size = Math.min(left.size(), right.size());
		for (int i = 0; i < size; i++) {
			int comparison = Integer.compare(left.get(i), right.get(i));
			if (comparison != 0) {
				return comparison;
			}
		}
		return Integer.compare(left.size(), right.size());
	}

